/* ============================ Finance ============================ */
function Finance({ index, onBack }) {
  const [inv, setInv] = useState(null);
  useEffect(() => { loadArr("hg2:invoices").then(setInv); }, []);
  const data = useMemo(() => {
    const m = {};
    index.forEach((x) => { if (!x.date) return; const k = x.date.slice(0, 7); (m[k] = m[k] || { inc: 0, exp: 0 }).inc += Number(x.price) || 0; });
    (inv || []).forEach((x) => { if (!x.date) return; const k = x.date.slice(0, 7); (m[k] = m[k] || { inc: 0, exp: 0 }).exp += Number(x.amount) || 0; });
    return Object.entries(m).map(([k, v]) => ({ k, label: `${HE_MONTHS[+k.split("-")[1] - 1]} ${k.split("-")[0]}`, ...v, profit: v.inc - v.exp })).sort((a, b) => b.k.localeCompare(a.k));
  }, [index, inv]);
  const totInc = data.reduce((s, r) => s + r.inc, 0);
  const totExp = data.reduce((s, r) => s + r.exp, 0);
  const maxV = Math.max(1, ...data.map((r) => Math.max(r.inc, r.exp)));

  return (
    <div className="hg2-flow">
      <FlowHead title="מרכז פיננסי" sub="הכנסות · הוצאות · רווח" onBack={onBack} />
      {inv === null ? <div className="hg2-busy">טוען…</div> : <>
        <div className="hg2-stats" style={{ gridTemplateColumns: "1fr 1fr 1fr" }}>
          <div className="hg2-stat"><span>הכנסות</span><b className="cy">{ils(totInc)}</b></div>
          <div className="hg2-stat"><span>הוצאות</span><b style={{ color: "var(--amber)" }}>{ils(totExp)}</b></div>
          <div className="hg2-stat"><span>רווח</span><b style={{ color: totInc - totExp >= 0 ? "var(--ok)" : "var(--red)" }}>{ils(totInc - totExp)}</b></div>
        </div>

        <div className="hg2-secttl"><Wallet size={15} /> לפי חודש</div>
        <div className="hg2-list">
          {data.length === 0 && <div className="hg2-empty"><Wallet size={30} /><div>אין נתונים פיננסיים</div><p>הכנסות מחושבות מההתקנות, הוצאות מהחשבוניות</p></div>}
          {data.map((r) => (
            <div className="hg2-finrow" key={r.k}>
              <div className="hg2-finrow-top"><b>{r.label}</b><span className={r.profit >= 0 ? "pos" : "neg"}>{r.profit >= 0 ? "רווח " : "הפסד "}{ils(Math.abs(r.profit))}</span></div>
              <div className="hg2-finbar"><span className="inc" style={{ width: (r.inc / maxV * 100) + "%" }} /></div>
              <div className="hg2-finbar"><span className="exp" style={{ width: (r.exp / maxV * 100) + "%" }} /></div>
              <div className="hg2-finrow-meta"><span className="cy">הכנסות {ils(r.inc)}</span><span className="am">הוצאות {ils(r.exp)}</span></div>
            </div>
          ))}
        </div>
        <div className="hg2-footnote" style={{ marginTop: 8 }}>הכנסות = סכום ההתקנות שדווחו · הוצאות = סכום החשבוניות שהוזנו. כל מה שתזין מתעדכן כאן אוטומטית.</div>
      </>}
    </div>
  );
}

/* ── Customer directory: merge duplicates by normalised name, sum income.
   Normalisation: trim, collapse spaces, drop a leading definite-article "ה".
   Used both for the customers view (dedup) and the install-form autocomplete. ── */
const normName = (s) => { let k = (s || "").trim().replace(/\s+/g, " "); if (k.length > 3 && k[0] === "ה") k = k.slice(1); return k.toLowerCase(); };
function customerDirectory(index) {
  const m = {};
  (index || []).forEach((x) => {
    const name = (x.customer || "").trim(); const phone = (x.phone || "").trim();
    if (!name && !phone) return;
    const key = normName(name) || ("#" + phone);
    if (!m[key]) m[key] = { phone: "", count: 0, revenue: 0, variants: {} };
    const e = m[key];
    e.count++; e.revenue += Number(x.price) || 0;
    if (phone && !e.phone) e.phone = phone;
    if (name) e.variants[name] = (e.variants[name] || 0) + 1;
  });
  return Object.values(m).map((e) => {
    const best = Object.entries(e.variants).sort((a, b) => b[1] - a[1])[0];
    return { name: best ? best[0] : "(ללא שם)", phone: e.phone, count: e.count, revenue: e.revenue };
  }).sort((a, b) => b.revenue - a.revenue);
}

/* ============================ New installation ============================ */
function NewInstall({ onCancel, onSave, onStartDraft, onDiscardDraft, resumeEntry, customers, showToast }) {
  const r = resumeEntry || null;
  const [contractor, setContractor] = useState(r ? r.contractor : null);
  const [phase, setPhase] = useState(r ? "running" : "pick"); // pick | running | done
  const [startTs, setStartTs] = useState(r ? r.startTs || Date.now() : null);
  const [endTs, setEndTs] = useState(null);
  const [now, setNow] = useState(Date.now());
  const [draftId, setDraftId] = useState(r ? r.id : null);
  const [photoFull, setPhotoFull] = useState(null);
  const [thumb, setThumb] = useState(r ? r.thumb || null : null);
  const [gallery, setGallery] = useState([]); // {full, thumb}
  const [video, setVideo] = useState(null);   // {dataUrl|null, poster, stored, sizeMB}
  const [busy, setBusy] = useState(false);
  const camRef = useRef(null); const galRef = useRef(null);
  const camPhotosRef = useRef(null); const galPhotosRef = useRef(null);
  const vidCamRef = useRef(null); const vidGalRef = useRef(null);

  const isMaster = CONTRACTORS.find((c) => c.id === contractor)?.master;
  const [f, setF] = useState(r
    ? { location: r.location || "", idType: r.idType || "רישוי", idNumber: r.idNumber || "", installType: r.installType || "", manufacturer: r.manufacturer || "", vehicleType: r.vehicleType || "", price: r.price ? String(r.price) : "", phone: r.phone || "", customer: r.customer || "", date: r.date || todayISO(), withItai: !!r.withItai }
    : { location: "", idType: "רישוי", idNumber: "", installType: "", manufacturer: "", vehicleType: "", price: "", phone: "", customer: "", date: todayISO(), withItai: false });

  useEffect(() => {
    if (phase !== "running") return;
    const t = setInterval(() => setNow(Date.now()), 1000);
    return () => clearInterval(t);
  }, [phase]);

  const elapsed = phase === "running" ? (now - startTs) / 1000 : (endTs && startTs ? (endTs - startTs) / 1000 : 0);

  const start = async () => {
    // Persist immediately as an in-progress draft so the report is never lost
    let entry = null;
    if (onStartDraft) { try { entry = await onStartDraft(contractor); } catch {} }
    const ts = entry ? entry.startTs : Date.now();
    if (entry) setDraftId(entry.id);
    setStartTs(ts); setNow(Date.now()); setPhase("running");
    showToast && showToast("ההתקנה התחילה — נשמרה כטיוטה");
  };
  const finish = () => { setEndTs(Date.now()); setPhase("done"); };
  const cancel = async () => {
    // Discard an empty draft on explicit cancel; keep it if real data was entered
    if (draftId && onDiscardDraft && !f.vehicleType && !f.idNumber && !f.location && !(Number(f.price) > 0)) {
      try { await onDiscardDraft(draftId); } catch {}
    }
    onCancel();
  };

  const onPhoto = async (e) => {
    const file = e.target.files?.[0]; if (!file) return;
    setBusy(true);
    try {
      const full = await compress(file, 1100, 0.6);
      const th = await compress(file, 130, 0.5);
      setPhotoFull(full); setThumb(th);
    } catch { showToast("טעינת התמונה נכשלה", "warn"); }
    setBusy(false);
    e.target.value = "";
  };

  const onGallery = async (e) => {
    const files = [...(e.target.files || [])]; if (!files.length) return;
    setBusy(true);
    try {
      for (const file of files) {
        const full = await compress(file, 1100, 0.6);
        const th = await compress(file, 160, 0.5);
        setGallery((g) => [...g, { full, thumb: th }]);
      }
    } catch { showToast("טעינת תמונה נכשלה", "warn"); }
    setBusy(false);
    e.target.value = "";
  };
  const removeGalleryItem = (i) => setGallery((g) => g.filter((_, idx) => idx !== i));

  const onVideo = async (e) => {
    const file = e.target.files?.[0]; if (!file) return;
    setBusy(true);
    try {
      const poster = await videoPoster(file);
      const sizeMB = file.size / 1048576;
      if (file.size <= 4 * 1048576) { const dataUrl = await fileToDataURL(file); setVideo({ dataUrl, poster, stored: true, sizeMB }); }
      else { setVideo({ dataUrl: null, poster, stored: false, sizeMB }); }
    } catch { showToast("טעינת הסרטון נכשלה", "warn"); }
    setBusy(false);
    e.target.value = "";
  };

  const save = () => {
    if (!f.vehicleType && !f.idNumber && !f.location) { showToast("מלא לפחות מיקום או רישוי", "warn"); return; }
    const durationSec = endTs && startTs ? Math.round((endTs - startTs) / 1000) : 0;
    onSave({
      contractor, location: f.location.trim(), idType: f.idType, idNumber: f.idNumber.trim(),
      installType: f.installType.trim(), manufacturer: f.manufacturer.trim(), vehicleType: f.vehicleType.trim(),
      price: Number(f.price) || 0, phone: f.phone.trim(), customer: f.customer.trim(), date: f.date,
      startTs, endTs, durationSec, thumb, withItai: f.withItai,
    }, photoFull, {
      galleryFull: gallery.map((g) => g.full),
      galleryThumbs: gallery.map((g) => g.thumb),
      video: video ? { dataUrl: video.dataUrl, poster: video.poster, stored: video.stored } : null,
    }, draftId);
  };

  /* ---- pick contractor ---- */
  if (phase === "pick") {
    return (
      <div className="hg2-flow">
        <FlowHead title="התקנה חדשה" sub="בחר קבלן / גיליון" onBack={cancel} />
        <div className="hg2-contractors">
          {CONTRACTORS.map((c) => (
            <button key={c.id} className={"hg2-cbtn" + (contractor === c.id ? " sel" : "")} onClick={() => setContractor(c.id)}>
              <Truck size={20} /><span>{c.name}</span>{c.master && <em>ראשי</em>}
            </button>
          ))}
        </div>
        <div className="hg2-flow-foot">
          <button className="hg2-btn ghost" onClick={cancel}>ביטול</button>
          <button className="hg2-btn primary big" disabled={!contractor} onClick={start}><Play size={20} /> התחל התקנה</button>
        </div>
      </div>
    );
  }

  /* ---- running / done : timer + form ---- */
  return (
    <div className="hg2-flow">
      <FlowHead title={cName(contractor)} sub={phase === "running" ? "התקנה פעילה" : "התקנה הסתיימה"} onBack={cancel} />

      <div className={"hg2-timer " + phase}>
        <div className="hg2-timer-clock">{fmtClock(elapsed)}</div>
        <div className="hg2-timer-label">{phase === "running" ? <><span className="hg2-rec" /> נמדד זמן התקנה</> : <>משך ההתקנה</>}</div>
        {phase === "running"
          ? <button className="hg2-stop" onClick={finish}><Square size={16} /> סיום התקנה</button>
          : <button className="hg2-resume" onClick={() => { setPhase("running"); setStartTs(Date.now() - (endTs - startTs)); setEndTs(null); }}>המשך מדידה</button>}
      </div>

      <div className="hg2-form">
        <Field icon={MapPin} label="מיקום ההתקנה"><input value={f.location} onChange={(e) => setF({ ...f, location: e.target.value })} placeholder="עיר / אתר" /></Field>

        <div className="hg2-field">
          <div className="hg2-flabel"><Hash size={15} /> מספר רישוי / שלדה</div>
          <div className="hg2-seg">
            <button className={f.idType === "רישוי" ? "on" : ""} onClick={() => setF({ ...f, idType: "רישוי" })}>רישוי</button>
            <button className={f.idType === "שלדה" ? "on" : ""} onClick={() => setF({ ...f, idType: "שלדה" })}>שלדה</button>
          </div>
          <input value={f.idNumber} onChange={(e) => setF({ ...f, idNumber: e.target.value })} placeholder={f.idType === "רישוי" ? "מספר רישוי" : "מספר שלדה"} dir="ltr" style={{ textAlign: "right" }} />
          <div className="hg2-photobtns">
            <label className="hg2-pbtn"><Camera size={17} /> צלם עכשיו<input type="file" accept="image/*" capture="environment" hidden onChange={onPhoto} /></label>
            <label className="hg2-pbtn"><ImageIcon size={17} /> מהגלריה<input type="file" accept="image/*" hidden onChange={onPhoto} /></label>
          </div>
          {busy && <div className="hg2-busy">מעבד תמונה…</div>}
          {photoFull && <div className="hg2-preview"><img src={photoFull} alt="" /><button onClick={() => { setPhotoFull(null); setThumb(null); }}><X size={15} /></button></div>}
        </div>

        <Field icon={Wrench} label="סוג התקנה"><input value={f.installType} onChange={(e) => setF({ ...f, installType: e.target.value })} placeholder="איתוראן / מצלמות / פעיל…" /></Field>
        <Field icon={Factory} label="יצרן"><input value={f.manufacturer} onChange={(e) => setF({ ...f, manufacturer: e.target.value })} placeholder="בובקט / וולוו / jcb…" /></Field>
        <Field icon={Tag} label="סוג כלי"><input value={f.vehicleType} onChange={(e) => setF({ ...f, vehicleType: e.target.value })} placeholder="צמה / משאית / רכב…" /></Field>
        <Field icon={DollarSign} label="מחיר (ש״ח)"><input type="number" inputMode="numeric" value={f.price} onChange={(e) => setF({ ...f, price: e.target.value })} placeholder="0" /></Field>

        {isMaster && <>
          <Field icon={User} label="שם לקוח">
            <input list="hg-cust-new" value={f.customer} placeholder="שם הלקוח · בחר לקוח קיים" autoComplete="off"
              onChange={(e) => { const v = e.target.value; const hit = (customers || []).find((c) => c.name === v); setF((p) => ({ ...p, customer: v, phone: hit && hit.phone ? hit.phone : p.phone })); }} />
            <datalist id="hg-cust-new">{(customers || []).map((c, i) => <option key={i} value={c.name}>{[c.phone, c.count + " התקנות"].filter(Boolean).join(" · ")}</option>)}</datalist>
          </Field>
          <Field icon={Phone} label="טלפון לקוח"><input value={f.phone} onChange={(e) => setF({ ...f, phone: e.target.value })} placeholder="05X-XXXXXXX · יתמלא אוטומטית מלקוח קיים" dir="ltr" style={{ textAlign: "right" }} /></Field>
        </>}

        <Field icon={Calendar} label="תאריך"><DateField value={f.date} onChange={(v) => setF({ ...f, date: v })} /></Field>

        <button type="button" className={"hg2-toggle" + (f.withItai ? " on" : "")} onClick={() => setF({ ...f, withItai: !f.withItai })}>
          <span className="hg2-toggle-box">{f.withItai && <CheckCircle2 size={15} />}</span>
          <span>בוצע יחד עם איתי (המתקין)</span>
        </button>

        <div className="hg2-mediasec">
          <div className="hg2-flabel"><Images size={15} /> תמונות ההתקנה</div>
          <div className="hg2-photobtns">
            <label className="hg2-pbtn"><Camera size={17} /> צלם<input type="file" accept="image/*" capture="environment" hidden onChange={onGallery} /></label>
            <label className="hg2-pbtn"><Images size={17} /> מהגלריה<input type="file" accept="image/*" multiple hidden onChange={onGallery} /></label>
          </div>
          {gallery.length > 0 && <div className="hg2-grid">{gallery.map((p, i) => (
            <div className="hg2-gitem" key={i}><img src={p.thumb} alt="" /><button onClick={() => removeGalleryItem(i)}><X size={13} /></button></div>
          ))}</div>}
        </div>

        <div className="hg2-mediasec">
          <div className="hg2-flabel"><Film size={15} /> סרטון התקנה</div>
          <div className="hg2-photobtns">
            <label className="hg2-pbtn"><Film size={17} /> צלם סרטון<input type="file" accept="video/*" capture="environment" hidden onChange={onVideo} /></label>
            <label className="hg2-pbtn"><ImageIcon size={17} /> מהגלריה<input type="file" accept="video/*" hidden onChange={onVideo} /></label>
          </div>
          {video && <div className="hg2-vidprev">
            {video.poster ? <img src={video.poster} alt="" /> : <div className="hg2-vidph"><Film size={24} /></div>}
            <div className="hg2-vidinfo">{video.stored
              ? <span className="ok"><CheckCircle2 size={13} /> הסרטון יישמר באפליקציה</span>
              : <span className="warn"><AlertTriangle size={13} /> סרטון כבד (~{video.sizeMB.toFixed(0)}MB) — יישמר רק כתמונת תצוגה. שמור את הקובץ עצמו ב-Drive.</span>}</div>
            <button className="hg2-vidx" onClick={() => setVideo(null)}><X size={15} /></button>
          </div>}
        </div>

        {(photoFull || gallery.length > 0 || (video && video.poster)) && (
          <div className="hg2-shotsum">
            <div className="hg2-flabel"><Images size={15} /> תמונות שצילמת ({(photoFull ? 1 : 0) + gallery.length + (video && video.poster ? 1 : 0)})</div>
            <div className="hg2-grid">
              {photoFull && <div className="hg2-gitem"><img src={thumb || photoFull} alt="" /></div>}
              {gallery.map((p, i) => <div className="hg2-gitem" key={i}><img src={p.thumb} alt="" /></div>)}
              {video && video.poster && <div className="hg2-gitem"><img src={video.poster} alt="" /><span className="hg2-vtag"><Film size={11} /></span></div>}
            </div>
          </div>
        )}
      </div>

      <div className="hg2-flow-foot">
        <button className="hg2-btn ghost" onClick={cancel}>ביטול</button>
        <button className="hg2-btn primary big" onClick={() => {
          if (phase === "running") { const end = Date.now(); setEndTs(end); setPhase("done"); const durationSec = startTs ? Math.round((end - startTs) / 1000) : 0;
            if (!f.vehicleType && !f.idNumber && !f.location) { showToast("מלא לפחות מיקום או רישוי", "warn"); return; }
            onSave({ contractor, location: f.location.trim(), idType: f.idType, idNumber: f.idNumber.trim(), installType: f.installType.trim(), manufacturer: f.manufacturer.trim(), vehicleType: f.vehicleType.trim(), price: Number(f.price) || 0, phone: f.phone.trim(), customer: f.customer.trim(), date: f.date, startTs, endTs: end, durationSec, thumb, withItai: f.withItai }, photoFull, { galleryFull: gallery.map((g) => g.full), galleryThumbs: gallery.map((g) => g.thumb), video: video ? { dataUrl: video.dataUrl, poster: video.poster, stored: video.stored } : null }, draftId);
          } else { save(); } }}>
          <CheckCircle2 size={20} /> {phase === "running" ? "סיים ושמור" : "שמור התקנה"}
        </button>
      </div>
    </div>
  );
}

/* ============================ Detail / Edit ============================ */
function Detail({ entry, onBack, onDelete, onUpdate, customers, showToast }) {
  const [photo, setPhoto] = useState(null);
  const [gallery, setGallery] = useState(null);
  const [video, setVideo] = useState(null);
  const [editing, setEditing] = useState(false);
  const [ef, setEf] = useState(null);
  const [existing, setExisting] = useState([]); // {full,thumb} kept
  const [added, setAdded] = useState([]);        // {full,thumb} new
  const [vid, setVid] = useState(undefined);     // undefined=unchanged, null=removed, {..}=new/current
  const [busy, setBusy] = useState(false);
  const pCamRef = useRef(null); const pGalRef = useRef(null); const vCamRef = useRef(null); const vGalRef = useRef(null);

  useEffect(() => {
    if (!entry) return;
    if (entry.hasPhoto) loadPhoto(entry.id).then(setPhoto);
    if (entry.photoCount > 0) loadGallery(entry.id).then(setGallery); else setGallery([]);
    if (entry.videoStored) loadVideo(entry.id).then(setVideo);
  }, [entry]);

  if (!entry) return <div className="hg2-flow"><FlowHead title="התקנה" onBack={onBack} /><div className="hg2-empty">לא נמצא</div></div>;

  const startEdit = () => {
    setEf({
      contractor: entry.contractor, date: entry.date || todayISO(), location: entry.location || "",
      idType: entry.idType || "רישוי", idNumber: entry.idNumber || "", installType: entry.installType || "",
      manufacturer: entry.manufacturer || "", vehicleType: entry.vehicleType || "", price: String(entry.price || ""),
      phone: entry.phone || "", customer: entry.customer || "", durMin: entry.durationSec ? Math.round(entry.durationSec / 60) : "", withItai: !!entry.withItai,
    });
    setExisting((gallery || []).map((full, i) => ({ full, thumb: (entry.photoThumbs || [])[i] || full })));
    setAdded([]); setVid(undefined); setEditing(true);
  };

  const addPhotos = async (e) => {
    const files = [...(e.target.files || [])]; if (!files.length) return; setBusy(true);
    try { for (const f of files) { const full = await compress(f, 1100, 0.6); const th = await compress(f, 160, 0.5); setAdded((a) => [...a, { full, thumb: th }]); } }
    catch { showToast("טעינת תמונה נכשלה", "warn"); }
    setBusy(false); e.target.value = "";
  };
  const addVideo = async (e) => {
    const file = e.target.files?.[0]; if (!file) return; setBusy(true);
    try {
      const poster = await videoPoster(file); const sizeMB = file.size / 1048576;
      if (file.size <= 4 * 1048576) { const dataUrl = await fileToDataURL(file); setVid({ dataUrl, poster, stored: true, sizeMB }); }
      else { setVid({ dataUrl: null, poster, stored: false, sizeMB }); }
    } catch { showToast("טעינת הסרטון נכשלה", "warn"); }
    setBusy(false); e.target.value = "";
  };

  const saveEdit = () => {
    const data = {
      contractor: ef.contractor, date: ef.date, location: ef.location.trim(), idType: ef.idType, idNumber: ef.idNumber.trim(),
      installType: ef.installType.trim(), manufacturer: ef.manufacturer.trim(), vehicleType: ef.vehicleType.trim(),
      price: Number(ef.price) || 0, phone: ef.phone.trim(), customer: ef.customer.trim(),
      durationSec: ef.durMin === "" ? entry.durationSec : Math.round(Number(ef.durMin) * 60), withItai: ef.withItai,
    };
    const galleryReady = entry.photoCount === 0 || gallery !== null;
    const ops = {};
    if (galleryReady) { ops.galleryChanged = true; ops.keepFulls = existing.map((p) => p.full); ops.keepThumbs = existing.map((p) => p.thumb); ops.newGalleryFull = added.map((p) => p.full); ops.newGalleryThumbs = added.map((p) => p.thumb); }
    if (vid !== undefined) { ops.videoChanged = true; ops.video = vid ? { dataUrl: vid.dataUrl, poster: vid.poster, stored: vid.stored } : null; }
    onUpdate(entry.id, data, ops);
    setEditing(false);
  };

  /* ---------- EDIT MODE ---------- */
  if (editing) {
    const isMaster = CONTRACTORS.find((c) => c.id === ef.contractor)?.master;
    return (
      <div className="hg2-flow">
        <FlowHead title="עריכת התקנה" sub="תיקון נתונים" onBack={() => setEditing(false)} />
        <div className="hg2-form">
          <Field icon={Truck} label="קבלן">
            <select value={ef.contractor} onChange={(e) => setEf({ ...ef, contractor: e.target.value })}>
              {CONTRACTORS.map((c) => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </Field>
          <Field icon={Calendar} label="תאריך"><DateField value={ef.date} onChange={(v) => setEf({ ...ef, date: v })} /></Field>
          <Field icon={MapPin} label="מיקום"><input value={ef.location} onChange={(e) => setEf({ ...ef, location: e.target.value })} /></Field>
          <div className="hg2-field">
            <div className="hg2-flabel"><Hash size={15} /> מספר רישוי / שלדה</div>
            <div className="hg2-seg">
              <button className={ef.idType === "רישוי" ? "on" : ""} onClick={() => setEf({ ...ef, idType: "רישוי" })}>רישוי</button>
              <button className={ef.idType === "שלדה" ? "on" : ""} onClick={() => setEf({ ...ef, idType: "שלדה" })}>שלדה</button>
            </div>
            <input value={ef.idNumber} onChange={(e) => setEf({ ...ef, idNumber: e.target.value })} dir="ltr" style={{ textAlign: "right" }} />
          </div>
          <Field icon={Wrench} label="סוג התקנה"><input value={ef.installType} onChange={(e) => setEf({ ...ef, installType: e.target.value })} /></Field>
          <Field icon={Factory} label="יצרן"><input value={ef.manufacturer} onChange={(e) => setEf({ ...ef, manufacturer: e.target.value })} /></Field>
          <Field icon={Tag} label="סוג כלי"><input value={ef.vehicleType} onChange={(e) => setEf({ ...ef, vehicleType: e.target.value })} /></Field>
          <Field icon={DollarSign} label="מחיר (ש״ח)"><input type="number" inputMode="numeric" value={ef.price} onChange={(e) => setEf({ ...ef, price: e.target.value })} /></Field>
          {isMaster && <>
            <Field icon={User} label="שם לקוח">
              <input list="hg-cust-edit" value={ef.customer} placeholder="שם הלקוח · בחר לקוח קיים" autoComplete="off"
                onChange={(e) => { const v = e.target.value; const hit = (customers || []).find((c) => c.name === v); setEf((p) => ({ ...p, customer: v, phone: hit && hit.phone ? hit.phone : p.phone })); }} />
              <datalist id="hg-cust-edit">{(customers || []).map((c, i) => <option key={i} value={c.name}>{[c.phone, c.count + " התקנות"].filter(Boolean).join(" · ")}</option>)}</datalist>
            </Field>
            <Field icon={Phone} label="טלפון לקוח"><input value={ef.phone} onChange={(e) => setEf({ ...ef, phone: e.target.value })} dir="ltr" style={{ textAlign: "right" }} placeholder="יתמלא אוטומטית מלקוח קיים" /></Field>
          </>}
          <Field icon={Timer} label="משך התקנה (דקות)"><input type="number" inputMode="numeric" value={ef.durMin} onChange={(e) => setEf({ ...ef, durMin: e.target.value })} placeholder="—" /></Field>
          <button type="button" className={"hg2-toggle" + (ef.withItai ? " on" : "")} onClick={() => setEf({ ...ef, withItai: !ef.withItai })}>
            <span className="hg2-toggle-box">{ef.withItai && <CheckCircle2 size={15} />}</span>
            <span>בוצע יחד עם איתי (המתקין)</span>
          </button>

          <div className="hg2-mediasec">
            <div className="hg2-flabel"><Images size={15} /> תמונות ההתקנה</div>
            {entry.photoCount > 0 && gallery === null && <div className="hg2-busy">טוען תמונות קיימות…</div>}
            <div className="hg2-photobtns">
              <label className="hg2-pbtn"><Camera size={17} /> צלם<input type="file" accept="image/*" capture="environment" hidden onChange={addPhotos} /></label>
              <label className="hg2-pbtn"><Images size={17} /> מהגלריה<input type="file" accept="image/*" multiple hidden onChange={addPhotos} /></label>
            </div>
            {(existing.length > 0 || added.length > 0) && <div className="hg2-grid">
              {existing.map((p, i) => <div className="hg2-gitem" key={"e" + i}><img src={p.thumb} alt="" /><button onClick={() => setExisting(existing.filter((_, x) => x !== i))}><X size={13} /></button></div>)}
              {added.map((p, i) => <div className="hg2-gitem" key={"a" + i}><img src={p.thumb} alt="" /><button onClick={() => setAdded(added.filter((_, x) => x !== i))}><X size={13} /></button></div>)}
            </div>}
          </div>

          <div className="hg2-mediasec">
            <div className="hg2-flabel"><Film size={15} /> סרטון התקנה</div>
            <div className="hg2-photobtns">
              <label className="hg2-pbtn"><Film size={17} /> צלם סרטון<input type="file" accept="video/*" capture="environment" hidden onChange={addVideo} /></label>
              <label className="hg2-pbtn"><ImageIcon size={17} /> מהגלריה<input type="file" accept="video/*" hidden onChange={addVideo} /></label>
            </div>
            {(() => {
              const showVid = vid !== undefined ? vid : (entry.hasVideo ? { poster: entry.videoPoster, stored: entry.videoStored, existing: true } : null);
              if (!showVid) return null;
              return <div className="hg2-vidprev">
                {showVid.poster ? <img src={showVid.poster} alt="" /> : <div className="hg2-vidph"><Film size={24} /></div>}
                <div className="hg2-vidinfo">{showVid.existing ? <span className="ok">סרטון קיים</span> : showVid.stored ? <span className="ok"><CheckCircle2 size={13} /> יישמר באפליקציה</span> : <span className="warn"><AlertTriangle size={13} /> סרטון כבד — תמונת תצוגה בלבד</span>}</div>
                <button className="hg2-vidx" onClick={() => setVid(null)}><X size={15} /></button>
              </div>;
            })()}
          </div>

          {busy && <div className="hg2-busy">מעבד מדיה…</div>}
        </div>
        <div className="hg2-flow-foot">
          <button className="hg2-btn ghost" onClick={() => setEditing(false)}>ביטול</button>
          <button className="hg2-btn primary big" onClick={saveEdit}><CheckCircle2 size={20} /> שמור שינויים</button>
        </div>
      </div>
    );
  }

  /* ---------- VIEW MODE ---------- */
  const rows = [
    ["מיקום", entry.location], [entry.idType || "רישוי", entry.idNumber], ["סוג התקנה", entry.installType],
    ["יצרן", entry.manufacturer], ["סוג כלי", entry.vehicleType], ["מחיר", ils(entry.price)],
    ...(entry.phone ? [["טלפון", entry.phone]] : []), ...(entry.customer ? [["לקוח", entry.customer]] : []),
    ["תאריך", dmy(entry.date)], ["משך התקנה", fmtDur(entry.durationSec)],
    ...(entry.withItai ? [["בוצע עם", "איתי (המתקין)"]] : []),
  ];
  return (
    <div className="hg2-flow">
      <FlowHead title={entry.vehicleType || "התקנה"} sub={cName(entry.contractor)} onBack={onBack} />
      <button className="hg2-editbtn" onClick={startEdit}><Pencil size={15} /> ערוך / תקן נתונים</button>
      {photo && <div className="hg2-detail-photo"><img src={photo} alt="" /></div>}
      {entry.hasPhoto && !photo && <div className="hg2-busy">טוען תמונה…</div>}
      <div className="hg2-detail">
        {rows.map(([k, v], i) => <div className="hg2-drow" key={i}><span>{k}</span><b>{v || "—"}</b></div>)}
      </div>

      {(entry.photoCount > 0 || entry.hasVideo) && <div className="hg2-medialabel"><Images size={14} /> תיעוד ההתקנה</div>}
      {gallery && gallery.length > 0 && <div className="hg2-gallery">{gallery.map((src, i) => <img key={i} src={src} alt="" />)}</div>}
      {entry.hasVideo && <div className="hg2-videobox">
        {video
          ? <video src={video} controls playsInline />
          : <div className="hg2-vidph big">{entry.videoPoster ? <img src={entry.videoPoster} alt="" /> : <Film size={28} />}<span>הסרטון נשמר מחוץ לאפליקציה — בגלריה / ב-Drive</span></div>}
      </div>}

      <div className="hg2-flow-foot">
        <button className="hg2-btn danger" onClick={() => onDelete(entry.id)}><Trash2 size={17} /> מחק התקנה</button>
      </div>
    </div>
  );
}

/* ============================ bits ============================ */
function FlowHead({ title, sub, onBack }) {
  return <div className="hg2-flowhead"><button className="hg2-back" onClick={onBack}><ChevronLeft size={22} /></button><div><h2>{title}</h2>{sub && <span>{sub}</span>}</div></div>;
}
function Field({ icon: I, label, children }) {
  return <label className="hg2-field"><div className="hg2-flabel">{I && <I size={15} />} {label}</div>{children}</label>;
}

/* ============================ styles ============================ */
function Styles() {
  return <style>{`
@import url('https://fonts.googleapis.com/css2?family=Rubik:wght@500;700;900&family=Heebo:wght@400;500;700&display=swap');
.hg2,.hg2 *{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}
.hg2{--void:#080B10;--s9:#10151D;--s8:#1A2230;--s7:#2B3543;--s4:#8E9BAB;--silver:#E8EEF4;--gold:#E4BC63;--gold2:#B6883A;--champ:#F7E8C0;--amber:#E4BC63;--amber2:#B6883A;--cyan:#6FD3F0;--ok:#3FD79A;--red:#FF5C50;
  font-family:'Heebo',sans-serif;background:radial-gradient(125% 75% at 50% -5%,#172230 0%,#0C1118 45%,var(--void) 100%);background-attachment:fixed;color:var(--silver);min-height:100vh;max-width:520px;margin:0 auto;padding:16px 14px 84px;font-size:15px}
.hg2 img{display:block}
.hg2 input{font-family:inherit}

.hg2-head{display:flex;align-items:center;gap:12px;padding:4px 2px 16px;position:relative}
.hg2-logo{width:46px;filter:drop-shadow(0 1px 6px rgba(228,188,99,.45))}
.hg2-name{font-family:'Rubik';font-weight:900;font-size:19px;letter-spacing:1.5px;background:linear-gradient(95deg,var(--gold2),var(--gold) 40%,var(--champ) 70%,var(--gold));-webkit-background-clip:text;background-clip:text;color:transparent}
.hg2-tag{font-size:10.5px;color:var(--gold);opacity:.8;letter-spacing:2px;font-weight:700}

.hg2-stats{display:grid;grid-template-columns:repeat(2,1fr);gap:9px;margin-bottom:14px}
.hg2-stat{background:var(--s9);border:1px solid var(--s7);border-radius:13px;padding:12px 14px}
.hg2-stat span{font-size:12px;color:var(--s4)}
.hg2-stat b{display:block;font-family:'Rubik';font-weight:900;font-size:21px;margin-top:3px}
.hg2-stat b.cy{color:var(--cyan)}

.hg2-msum{background:var(--s9);border:1px solid var(--s7);border-radius:14px;padding:13px 14px;margin-bottom:16px}
.hg2-msum-head{display:flex;align-items:center;justify-content:space-between;margin-bottom:11px;padding-bottom:10px;border-bottom:1px solid var(--s7)}
.hg2-msum-head>span{display:flex;align-items:center;gap:6px;font-family:'Rubik';font-weight:700;font-size:14px;color:var(--silver)}
.hg2-msum-head>b{font-family:'Rubik';font-weight:900;font-size:18px}
.hg2-msum-head>b.cy{color:var(--cyan)}
.hg2-msum-rows{display:flex;flex-direction:column;gap:8px}
.hg2-msum-row{display:flex;align-items:center;gap:9px;padding:8px 10px;background:var(--s8);border:1px solid var(--s7);border-radius:10px}
.hg2-msum-row.idle{opacity:.5}
.hg2-msum-name{font-weight:700;font-size:13.5px;color:var(--amber);flex-shrink:0;min-width:62px}
.hg2-msum-cnt{font-size:12px;color:var(--s4);flex:1}
.hg2-msum-time{display:flex;align-items:center;gap:3px;font-size:11px;color:var(--cyan);flex-shrink:0}
.hg2-msum-rev{font-family:ui-monospace,monospace;font-weight:700;font-size:13.5px;color:var(--silver);flex-shrink:0;white-space:nowrap}
.hg2-msum-foot{margin-top:10px;text-align:center;font-size:11.5px;color:var(--s4)}

.hg2-expbox{background:var(--s9);border:1px solid var(--s7);border-radius:14px;padding:13px 14px;margin-bottom:14px}
.hg2-expbox-h{display:flex;align-items:center;gap:7px;font-family:'Rubik';font-weight:700;font-size:14px;color:var(--silver);margin-bottom:10px}
.hg2-expbox-row{display:flex;gap:8px;margin-bottom:10px}
.hg2-expsel{flex:1;min-width:0;background:var(--s8);border:1px solid var(--s7);color:var(--silver);border-radius:10px;padding:10px 11px;font-family:inherit;font-size:13.5px;outline:none}
.hg2-expbtn{width:100%;display:flex;align-items:center;justify-content:center;gap:8px;background:linear-gradient(135deg,#1E7A52,#279E69);color:#fff;border:none;border-radius:11px;padding:13px;font-family:'Rubik';font-weight:900;font-size:15px;cursor:pointer;box-shadow:0 6px 18px rgba(30,140,90,.3)}
.hg2-expbtn:active{transform:scale(.985)}

.hg2-add{width:100%;display:flex;align-items:center;justify-content:center;gap:9px;background:linear-gradient(135deg,var(--champ),var(--gold) 45%,var(--gold2));color:#241A06;border:none;border-radius:14px;padding:16px;font-family:'Rubik';font-weight:900;font-size:17px;cursor:pointer;box-shadow:0 8px 26px rgba(228,188,99,.32),inset 0 1px 0 rgba(255,255,255,.35);margin-bottom:18px}
.hg2-add:active{transform:scale(.985)}

.hg2-listhead{display:flex;justify-content:space-between;align-items:center;margin-bottom:10px}
.hg2-listhead>span{font-family:'Rubik';font-weight:700;font-size:15px}
.hg2-export{display:flex;align-items:center;gap:6px;background:var(--s8);border:1px solid var(--s7);color:var(--silver);border-radius:9px;padding:7px 11px;font-family:inherit;font-size:12.5px;font-weight:700;cursor:pointer}
.hg2-export:active{border-color:var(--cyan)}

.hg2-search{display:flex;align-items:center;gap:9px;background:var(--s9);border:1px solid var(--s7);border-radius:11px;padding:11px 13px;margin-bottom:10px;color:var(--s4)}
.hg2-search input{flex:1;background:none;border:none;outline:none;color:var(--silver);font-size:15px;font-family:inherit;min-width:0}
.hg2-search button{background:none;border:none;color:var(--s4);cursor:pointer;display:flex;padding:0}
.hg2-filters{display:flex;gap:7px;overflow-x:auto;padding-bottom:8px;margin-bottom:6px;-ms-overflow-style:none;scrollbar-width:none}
.hg2-filters::-webkit-scrollbar{display:none}
.hg2-fchip{flex-shrink:0;background:var(--s8);border:1px solid var(--s7);color:var(--s4);border-radius:20px;padding:7px 15px;font-family:inherit;font-size:13px;font-weight:700;cursor:pointer;white-space:nowrap}
.hg2-fchip.on{background:rgba(228,188,99,.14);border-color:var(--amber);color:var(--amber)}

.hg2-list{display:flex;flex-direction:column;gap:9px}
.hg2-card{display:flex;align-items:stretch;gap:11px;width:100%;background:var(--s9);border:1px solid var(--s7);border-radius:13px;padding:10px;cursor:pointer;text-align:right;font-family:inherit;color:inherit}
.hg2-card:active{border-color:var(--cyan)}
.hg2-card-thumb{width:54px;height:54px;border-radius:10px;overflow:hidden;flex-shrink:0;background:var(--s8);display:flex;align-items:center;justify-content:center;color:var(--s4)}
.hg2-card-thumb img{width:100%;height:100%;object-fit:cover}
.hg2-card-mid{flex:1;min-width:0;display:flex;flex-direction:column;gap:3px}
.hg2-card-top{display:flex;align-items:center;gap:7px;justify-content:space-between}
.hg2-card-top b{font-size:14px;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.hg2-chip{font-size:10.5px;font-weight:700;color:var(--amber);background:rgba(228,188,99,.13);padding:2px 7px;border-radius:20px;white-space:nowrap;flex-shrink:0}
.hg2-card-sub{font-size:12px;color:var(--s4);white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.hg2-card-meta{display:flex;gap:11px;font-size:11px;color:var(--s4);flex-wrap:wrap;margin-top:1px}
.hg2-card-meta span{display:flex;align-items:center;gap:3px}
.hg2-card-meta .ti{color:var(--cyan)}
.hg2-card-price{font-family:ui-monospace,monospace;font-weight:700;color:var(--silver);font-size:14px;align-self:center;white-space:nowrap}
.hg2-drafts{margin-bottom:10px}
.hg2-card-draft{border:1.5px solid rgba(228,99,99,.4)!important;background:linear-gradient(180deg,rgba(228,99,99,.07),rgba(228,99,99,.02))!important}
.hg2-card-thumb.draft{display:flex;align-items:center;justify-content:center;background:rgba(228,99,99,.12)}
.hg2-card-resume{align-self:center;display:flex;align-items:center;gap:5px;background:var(--cyan,#3fb8c4);color:#04141a;border-radius:9px;padding:8px 12px;font-weight:800;font-size:12.5px;white-space:nowrap}

.hg2-empty{text-align:center;color:var(--s4);padding:46px 20px}
.hg2-empty svg{opacity:.4;margin-bottom:10px}
.hg2-empty div{font-weight:700;color:var(--silver);margin-bottom:5px}
.hg2-empty p{font-size:13px;line-height:1.5}
.hg2-footnote{font-size:11.5px;color:var(--s4);text-align:center;margin-top:18px;line-height:1.6;padding:0 10px}
.hg2-reset{display:flex;align-items:center;justify-content:center;gap:6px;margin:14px auto 0;background:none;border:1px solid var(--s7);color:var(--s4);border-radius:9px;padding:9px 16px;font-family:inherit;font-size:12.5px;cursor:pointer}
.hg2-reset:active{border-color:var(--red);color:var(--red)}

.hg2-tabbar{position:fixed;bottom:0;left:50%;transform:translateX(-50%);width:100%;max-width:520px;display:flex;background:rgba(11,15,20,.93);backdrop-filter:blur(10px);border-top:1px solid var(--s7);z-index:40}
.hg2-tabbar button{flex:1;display:flex;flex-direction:column;align-items:center;gap:3px;background:none;border:none;color:var(--s4);padding:11px 0 14px;font-family:inherit;font-size:11px;font-weight:700;cursor:pointer}
.hg2-tabbar button.on{color:var(--amber)}
.hg2-tabbar button.on svg{filter:drop-shadow(0 0 6px rgba(228,188,99,.4))}

.hg2-analysec{background:var(--s9);border:1px solid var(--s7);border-radius:14px;padding:15px;margin-bottom:14px}
.hg2-analyhead{display:flex;align-items:center;gap:8px;font-family:'Rubik';font-weight:700;font-size:15px;margin-bottom:13px}
.hg2-analyhead svg{color:var(--amber)}
.hg2-month{padding:11px 0;border-bottom:1px solid var(--s7)}
.hg2-month:last-child{border:none;padding-bottom:0}
.hg2-month-top{display:flex;justify-content:space-between;align-items:baseline;margin-bottom:7px}
.hg2-month-top b{font-size:14.5px;font-weight:700}
.hg2-month-rev{font-family:ui-monospace,monospace;font-weight:700;color:var(--cyan);font-size:14px}
.hg2-bar{height:7px;background:var(--s8);border-radius:5px;overflow:hidden}
.hg2-bar span{display:block;height:100%;background:linear-gradient(90deg,var(--amber2),var(--amber));border-radius:5px}
.hg2-bar.sm{height:5px}
.hg2-month-meta{display:flex;gap:14px;flex-wrap:wrap;font-size:11.5px;color:var(--s4);margin-top:8px}
.hg2-month-meta span{display:flex;align-items:center;gap:4px}
.hg2-month-meta .ti{color:var(--cyan)}
.hg2-rank{display:flex;align-items:center;gap:11px;padding:9px 0;border-bottom:1px solid var(--s7)}
.hg2-rank:last-child{border:none;padding-bottom:0}
.hg2-rank-n{width:22px;height:22px;border-radius:7px;background:var(--s8);color:var(--s4);font-weight:900;font-size:12px;display:flex;align-items:center;justify-content:center;flex-shrink:0}
.hg2-rank:first-child .hg2-rank-n{background:var(--amber);color:#1A1206}
.hg2-rank-mid{flex:1;min-width:0}
.hg2-rank-top{display:flex;justify-content:space-between;align-items:baseline;gap:8px;margin-bottom:5px}
.hg2-rank-top b{font-size:13.5px;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.hg2-rank-top>span{font-family:ui-monospace,monospace;font-size:12.5px;color:var(--silver);flex-shrink:0}
.hg2-rank-c{font-size:12px;color:var(--s4);flex-shrink:0;min-width:30px;text-align:left}

/* flow */
.hg2-flow{display:flex;flex-direction:column;min-height:calc(100vh - 46px)}
.hg2-flowhead{display:flex;align-items:center;gap:6px;padding:2px 0 16px}
.hg2-back{background:var(--s8);border:1px solid var(--s7);color:var(--silver);width:38px;height:38px;border-radius:10px;display:flex;align-items:center;justify-content:center;cursor:pointer;flex-shrink:0}
.hg2-flowhead h2{font-family:'Rubik';font-weight:900;font-size:19px}
.hg2-flowhead span{font-size:12.5px;color:var(--cyan);font-weight:700}

.hg2-contractors{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:auto}
.hg2-cbtn{position:relative;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:8px;background:var(--s9);border:1.5px solid var(--s7);color:var(--silver);border-radius:14px;padding:22px 10px;cursor:pointer;font-family:inherit;font-size:14px;font-weight:700}
.hg2-cbtn svg{color:var(--s4)}
.hg2-cbtn.sel{border-color:var(--amber);background:rgba(228,188,99,.08)}
.hg2-cbtn.sel svg{color:var(--amber)}
.hg2-cbtn em{position:absolute;top:8px;left:8px;font-style:normal;font-size:9px;color:var(--cyan);background:rgba(43,196,240,.13);padding:2px 6px;border-radius:10px}

/* timer */
.hg2-timer{background:var(--s9);border:1px solid var(--s7);border-radius:16px;padding:20px;text-align:center;margin-bottom:16px}
.hg2-timer.running{border-color:rgba(43,196,240,.4);box-shadow:0 0 24px rgba(43,196,240,.1)}
.hg2-timer.done{border-color:rgba(53,208,138,.4)}
.hg2-timer-clock{font-family:ui-monospace,'SF Mono',monospace;font-weight:700;font-size:46px;letter-spacing:2px;color:#fff;font-variant-numeric:tabular-nums}
.hg2-timer.done .hg2-timer-clock{color:var(--ok)}
.hg2-timer-label{display:flex;align-items:center;justify-content:center;gap:7px;font-size:12.5px;color:var(--s4);margin:6px 0 14px}
.hg2-rec{width:9px;height:9px;border-radius:50%;background:var(--red);animation:blink 1.1s infinite}
@keyframes blink{0%,100%{opacity:1}50%{opacity:.25}}
.hg2-stop{display:inline-flex;align-items:center;gap:8px;background:var(--red);color:#fff;border:none;border-radius:11px;padding:12px 26px;font-family:'Rubik';font-weight:700;font-size:15px;cursor:pointer}
.hg2-resume{background:var(--s8);border:1px solid var(--s7);color:var(--silver);border-radius:11px;padding:9px 18px;font-family:inherit;font-weight:700;font-size:13px;cursor:pointer}

/* form */
.hg2-form{display:flex;flex-direction:column;gap:13px;margin-bottom:18px}
.hg2-field{display:flex;flex-direction:column;gap:7px}
.hg2-flabel{display:flex;align-items:center;gap:6px;font-size:13px;color:var(--s4);font-weight:500}
.hg2-flabel svg{color:var(--amber)}
.hg2-field input{background:var(--s9);border:1.5px solid var(--s7);border-radius:11px;padding:13px 14px;color:var(--silver);font-size:16px;outline:none;width:100%}
.hg2-field input:focus{border-color:var(--cyan)}
.hg2-seg{display:flex;gap:0;background:var(--s8);border:1px solid var(--s7);border-radius:10px;overflow:hidden;width:fit-content}
.hg2-seg button{background:none;border:none;color:var(--s4);padding:7px 20px;font-family:inherit;font-size:13px;font-weight:700;cursor:pointer}
.hg2-seg button.on{background:var(--amber);color:#1A1206}
.hg2-photobtns{display:flex;gap:9px}
.hg2-pbtn{flex:1;display:flex;align-items:center;justify-content:center;gap:7px;background:var(--s8);border:1.5px dashed var(--s7);color:var(--silver);border-radius:11px;padding:12px;font-family:inherit;font-size:13.5px;font-weight:700;cursor:pointer}
.hg2-pbtn:active{border-color:var(--cyan);border-style:solid}
.hg2-pbtn svg{color:var(--cyan)}
.hg2-busy{font-size:12.5px;color:var(--cyan);text-align:center;padding:4px}
.hg2-preview{position:relative;border-radius:12px;overflow:hidden;border:1px solid var(--s7);margin-top:4px}
.hg2-preview img{width:100%;max-height:220px;object-fit:cover}
.hg2-preview button{position:absolute;top:8px;left:8px;background:rgba(11,15,20,.8);border:none;color:#fff;width:30px;height:30px;border-radius:8px;display:flex;align-items:center;justify-content:center;cursor:pointer}

.hg2-mediasec{display:flex;flex-direction:column;gap:9px;padding-top:13px;border-top:1px dashed var(--s7)}
.hg2-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(78px,1fr));gap:8px}
.hg2-gitem{position:relative;aspect-ratio:1;border-radius:10px;overflow:hidden;border:1px solid var(--s7)}
.hg2-shotsum{margin-top:14px;padding:14px;background:linear-gradient(160deg,rgba(228,188,99,.07),var(--s9) 70%);border:1px solid rgba(228,188,99,.3);border-radius:14px;display:flex;flex-direction:column;gap:10px}
.hg2-shotsum .hg2-flabel svg{color:var(--gold)}
.hg2-vtag{position:absolute;bottom:4px;right:4px;background:rgba(8,11,16,.8);color:var(--champ);border-radius:6px;width:20px;height:20px;display:flex;align-items:center;justify-content:center}
.hg2-gitem img{width:100%;height:100%;object-fit:cover}
.hg2-gitem button{position:absolute;top:4px;left:4px;background:rgba(11,15,20,.82);border:none;color:#fff;width:22px;height:22px;border-radius:6px;display:flex;align-items:center;justify-content:center;cursor:pointer}
.hg2-vidprev{display:flex;align-items:center;gap:11px;background:var(--s8);border:1px solid var(--s7);border-radius:12px;padding:10px}
.hg2-vidprev>img{width:62px;height:62px;border-radius:9px;object-fit:cover;flex-shrink:0}
.hg2-vidph{width:62px;height:62px;border-radius:9px;background:var(--s7);display:flex;align-items:center;justify-content:center;color:var(--s4);flex-shrink:0}
.hg2-vidinfo{flex:1;font-size:12px;line-height:1.45}
.hg2-vidinfo .ok{display:flex;align-items:center;gap:5px;color:var(--ok)}
.hg2-vidinfo .warn{display:flex;align-items:flex-start;gap:5px;color:var(--amber)}
.hg2-vidinfo svg{flex-shrink:0;margin-top:1px}
.hg2-vidx{background:none;border:none;color:var(--s4);cursor:pointer;flex-shrink:0;align-self:flex-start}

.hg2-medialabel{display:flex;align-items:center;gap:7px;font-family:'Rubik';font-weight:700;font-size:14px;margin:4px 0 11px}
.hg2-medialabel svg{color:var(--amber)}
.hg2-editbtn{display:flex;align-items:center;justify-content:center;gap:7px;width:100%;background:var(--s8);border:1px solid var(--s7);color:var(--silver);border-radius:11px;padding:11px;font-family:inherit;font-size:14px;font-weight:700;cursor:pointer;margin-bottom:14px}
.hg2-editbtn:active{border-color:var(--cyan)}
.hg2-editbtn svg{color:var(--cyan)}
.hg2-gallery{display:grid;grid-template-columns:repeat(auto-fill,minmax(100px,1fr));gap:8px;margin-bottom:14px}
.hg2-gallery img{width:100%;aspect-ratio:1;object-fit:cover;border-radius:11px;border:1px solid var(--s7)}
.hg2-videobox{margin-bottom:16px;border-radius:13px;overflow:hidden;border:1px solid var(--s7)}
.hg2-videobox video{width:100%;display:block;background:#000;max-height:320px}
.hg2-vidph.big{width:100%;height:auto;aspect-ratio:16/9;border-radius:0;flex-direction:column;gap:9px;position:relative;padding:16px;text-align:center}
.hg2-vidph.big img{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;opacity:.5}
.hg2-vidph.big span{position:relative;font-size:12.5px;color:var(--silver);background:rgba(11,15,20,.6);padding:6px 10px;border-radius:8px}

/* foot buttons */
.hg2-flow-foot{display:flex;gap:10px;margin-top:auto;padding-top:8px;position:sticky;bottom:0;background:linear-gradient(180deg,transparent,var(--void) 30%);padding-bottom:4px}
.hg2-btn{flex:1;display:flex;align-items:center;justify-content:center;gap:8px;border:none;border-radius:13px;padding:15px;font-family:'Rubik';font-weight:700;font-size:15px;cursor:pointer}
.hg2-btn.big{flex:2}
.hg2-btn.primary{background:linear-gradient(135deg,var(--champ),var(--gold) 45%,var(--gold2));color:#241A06;box-shadow:0 4px 16px rgba(228,188,99,.26),inset 0 1px 0 rgba(255,255,255,.3)}
.hg2-btn.primary:disabled{opacity:.4}
.hg2-btn.ghost{background:var(--s8);border:1px solid var(--s7);color:var(--silver)}
.hg2-btn.danger{background:rgba(255,82,71,.12);border:1px solid rgba(255,82,71,.4);color:#FF8077}

/* detail */
.hg2-detail-photo{border-radius:14px;overflow:hidden;border:1px solid var(--s7);margin-bottom:14px}
.hg2-detail-photo img{width:100%;max-height:300px;object-fit:cover}
.hg2-detail{background:var(--s9);border:1px solid var(--s7);border-radius:14px;overflow:hidden;margin-bottom:18px}
.hg2-drow{display:flex;justify-content:space-between;align-items:center;padding:13px 15px;border-bottom:1px solid var(--s7);font-size:14.5px}
.hg2-drow:last-child{border:none}
.hg2-drow span{color:var(--s4);font-size:13px}
.hg2-drow b{font-weight:700;text-align:left;max-width:62%}

/* toast + splash */
.hg2-toast{position:fixed;bottom:20px;left:50%;transform:translateX(-50%);display:flex;align-items:center;gap:9px;background:var(--s8);border:1px solid var(--s7);border-radius:12px;padding:13px 18px;font-size:14px;font-weight:500;z-index:60;box-shadow:0 10px 36px rgba(0,0,0,.5);max-width:92vw}
.hg2-toast.ok{border-color:rgba(53,208,138,.4)}.hg2-toast.ok svg{color:var(--ok)}
.hg2-toast.warn{border-color:rgba(228,188,99,.4)}.hg2-toast.warn svg{color:var(--amber)}
.hg2-splash{min-height:90vh;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:20px}
.hg2-splash-logo{width:96px;filter:drop-shadow(0 0 22px rgba(43,196,240,.35));animation:fl 3s ease-in-out infinite}
@keyframes fl{0%,100%{transform:translateY(0)}50%{transform:translateY(-7px)}}
.hg2-splash-bar{width:150px;height:3px;background:#1A2230;border-radius:3px;overflow:hidden}
.hg2-splash-bar span{display:block;height:100%;width:40%;background:linear-gradient(90deg,transparent,var(--cyan),transparent);animation:ld 1.2s infinite}
@keyframes ld{from{transform:translateX(-150px)}to{transform:translateX(390px)}}

/* hub */
.hg2-hubsum{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px}
.hg2-hubsum>div{background:var(--s9);border:1px solid var(--s7);border-radius:13px;padding:13px 15px}
.hg2-hubsum span{font-size:12px;color:var(--s4)}
.hg2-hubsum b{display:block;font-family:'Rubik';font-weight:900;font-size:22px;margin-top:3px}
.hg2-hubsum b.cy{color:var(--cyan)}
.hg2-hubgrid{display:grid;grid-template-columns:1fr 1fr;gap:11px;margin-top:18px}
.hg2-cmd{background:linear-gradient(150deg,#16202C,#0E141C 75%);border:1px solid var(--s7);border-radius:18px;padding:18px;margin-bottom:16px;box-shadow:0 8px 28px rgba(0,0,0,.35);position:relative;overflow:hidden}
.hg2-cmd::before{content:"";position:absolute;top:-40%;right:-10%;width:160px;height:160px;background:radial-gradient(circle,rgba(228,188,99,.16),transparent 70%);pointer-events:none}
.hg2-cmd-main span{font-size:12px;color:var(--s4);letter-spacing:.5px}
.hg2-cmd-main b{display:block;font-family:'Rubik';font-weight:900;font-size:34px;line-height:1.1;margin:3px 0;background:linear-gradient(95deg,var(--champ),var(--gold));-webkit-background-clip:text;background-clip:text;color:transparent}
.hg2-cmd-main em{font-style:normal;font-size:11.5px;color:var(--s4)}
.hg2-cmd-chips{display:flex;gap:8px;margin-top:14px}
.hg2-cmdchip{flex:1;display:flex;flex-direction:column;align-items:center;gap:2px;background:rgba(255,255,255,.03);border:1px solid var(--s7);border-radius:11px;padding:9px 6px;cursor:pointer;font-family:inherit;color:var(--silver)}
.hg2-cmdchip svg{color:var(--gold)}
.hg2-cmdchip b{font-family:'Rubik';font-weight:900;font-size:14px}
.hg2-cmdchip span{font-size:10px;color:var(--s4)}
.hg2-cmdchip.alert{border-color:rgba(255,92,80,.5)}
.hg2-cmdchip.alert svg{color:var(--red)}
.hg2-cmdchip.alert b{color:var(--red)}
.hg2-bkreminder{width:100%;display:flex;align-items:center;gap:11px;background:linear-gradient(135deg,rgba(228,188,99,.16),var(--s9) 70%);border:1px solid rgba(228,188,99,.45);border-radius:13px;padding:13px 15px;margin-bottom:14px;cursor:pointer;font-family:inherit;color:var(--silver);text-align:right}
.hg2-bkreminder>svg:first-child{color:var(--gold);flex-shrink:0}
.hg2-bkreminder div{flex:1}
.hg2-bkreminder b{display:block;font-size:14px;font-weight:700}
.hg2-bkreminder span{font-size:11.5px;color:var(--s4)}
.hg2-bkreminder>svg:last-child{color:var(--s4);flex-shrink:0}
.hg2-tile{position:relative;display:flex;flex-direction:column;align-items:flex-start;gap:6px;background:linear-gradient(160deg,#141B25,var(--s9) 70%);border:1px solid var(--s7);border-radius:16px;padding:17px 15px;cursor:pointer;text-align:right;font-family:inherit;color:var(--silver);min-height:106px;justify-content:center;box-shadow:0 2px 10px rgba(0,0,0,.25)}
.hg2-tile:active{transform:scale(.98)}
.hg2-tile svg{color:var(--gold);margin-bottom:2px;filter:drop-shadow(0 1px 4px rgba(228,188,99,.25))}
.hg2-tile b{font-family:'Rubik';font-weight:700;font-size:15px}
.hg2-tile em{font-style:normal;font-size:11.5px;color:var(--s4)}
.hg2-tile.hot{border-color:rgba(228,188,99,.55);background:linear-gradient(155deg,rgba(228,188,99,.16),#141B25 55%);box-shadow:0 6px 22px rgba(228,188,99,.14)}
.hg2-tile.hot svg{color:var(--gold)}
.hg2-tile.soon{opacity:.72}
.hg2-tile.soon svg{color:var(--s4)}
.hg2-soon{position:absolute;top:10px;left:10px;font-size:9px;font-weight:700;color:var(--gold);background:rgba(228,188,99,.14);padding:2px 7px;border-radius:10px}

/* stub */
.hg2-stub{text-align:center;padding:40px 22px;background:var(--s9);border:1px solid var(--s7);border-radius:16px}
.hg2-stub-ic{width:78px;height:78px;border-radius:50%;background:var(--s8);display:flex;align-items:center;justify-content:center;color:var(--cyan);margin:0 auto 16px}
.hg2-stub-t{font-family:'Rubik';font-weight:900;font-size:19px;margin-bottom:8px}
.hg2-stub-p{color:var(--s4);font-size:13.5px;margin-bottom:16px}
.hg2-stub-list{list-style:none;display:flex;flex-direction:column;gap:9px;text-align:right;max-width:340px;margin:0 auto}
.hg2-stub-list li{position:relative;padding-right:20px;font-size:13.5px;color:var(--silver);line-height:1.5}
.hg2-stub-list li::before{content:'';position:absolute;right:0;top:8px;width:7px;height:7px;border-radius:50%;background:var(--amber)}

/* toggle */
.hg2-toggle{display:flex;align-items:center;gap:11px;width:100%;background:var(--s9);border:1.5px solid var(--s7);border-radius:11px;padding:13px 14px;cursor:pointer;font-family:inherit;font-size:14.5px;font-weight:700;color:var(--silver)}
.hg2-toggle.on{border-color:var(--amber);background:rgba(228,188,99,.07)}
.hg2-toggle-box{width:24px;height:24px;border-radius:7px;border:1.5px solid var(--s7);display:flex;align-items:center;justify-content:center;color:#1A1206;flex-shrink:0}
.hg2-toggle.on .hg2-toggle-box{background:var(--amber);border-color:var(--amber)}

/* module rows / sections */
.hg2-secttl{display:flex;align-items:center;gap:8px;font-family:'Rubik';font-weight:700;font-size:15px;margin:6px 0 11px}
.hg2-secttl svg{color:var(--amber)}
.hg2-mini{margin-right:auto;display:flex;align-items:center;gap:5px;background:var(--s8);border:1px solid var(--s7);color:var(--silver);border-radius:8px;padding:6px 11px;font-family:inherit;font-size:12.5px;font-weight:700;cursor:pointer}
.hg2-mini.block{margin:0 0 12px;width:100%;justify-content:center;padding:11px}
.hg2-crow{display:flex;align-items:center;gap:11px;background:var(--s9);border:1px solid var(--s7);border-radius:12px;padding:11px 13px}
.hg2-crow-ic{width:38px;height:38px;border-radius:10px;background:var(--s8);display:flex;align-items:center;justify-content:center;color:var(--cyan);flex-shrink:0}
.hg2-crow-ic.t-0{color:#2BC4F0}.hg2-crow-ic.t-1{color:#35D08A}.hg2-crow-ic.t-2{color:#F0A22E}.hg2-crow-ic.t-3{color:#FF5247}
.hg2-crow-mid{flex:1;min-width:0;display:flex;flex-direction:column;gap:2px}
.hg2-crow-mid b{font-size:14px;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.hg2-crow-mid span{font-size:12px;color:var(--s4);white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.hg2-crow-rev{font-family:ui-monospace,monospace;font-weight:700;color:var(--cyan);font-size:13.5px;white-space:nowrap}
.hg2-crow-acts{display:flex;gap:6px;align-items:center;flex-shrink:0}
.hg2-icbtn2{background:var(--s8);border:1px solid var(--s7);color:var(--s4);width:30px;height:30px;border-radius:8px;display:flex;align-items:center;justify-content:center;cursor:pointer}
.hg2-icbtn2.d:active{color:var(--red);border-color:var(--red)}
.hg2-wa{width:32px;height:32px;border-radius:8px;background:rgba(53,208,138,.14);color:var(--ok);display:flex;align-items:center;justify-content:center;text-decoration:none}

/* modal */
.hg2-overlay{position:fixed;inset:0;background:rgba(5,8,12,.74);backdrop-filter:blur(4px);display:flex;align-items:flex-end;justify-content:center;z-index:1200;padding:0}
.hg2-modal{background:var(--s9);border:1px solid var(--s7);border-radius:18px 18px 0 0;width:100%;max-width:520px;padding-bottom:8px;animation:slideup .25s}
.hg2-modal-head{display:flex;justify-content:space-between;align-items:center;padding:18px 20px;border-bottom:1px solid var(--s7)}
.hg2-modal-head h3{font-family:'Rubik';font-weight:900;font-size:18px}
.hg2-modal-head button{background:none;border:none;color:var(--s4);cursor:pointer}
.hg2-modal .hg2-form{padding:18px 20px}
.hg2-modal-foot{display:flex;gap:10px;padding:4px 20px 16px}
.hg2-modal-foot .hg2-btn{flex:1}

/* segments full / wrap, compselect, quote */
.hg2-seg.full{width:100%;margin-bottom:16px}
.hg2-seg.full button{flex:1}
.hg2-seg.wrap{flex-wrap:wrap;width:100%}
.hg2-seg.wrap button{flex:1}
.hg2-compselect{background:var(--s9);border:1.5px solid var(--s7);border-radius:11px;padding:12px 13px;color:var(--silver);font-size:15px;font-family:inherit;width:100%;cursor:pointer}
.hg2-complist{display:flex;flex-direction:column;gap:7px}
.hg2-comprow{display:grid;grid-template-columns:1fr 64px 80px 30px;gap:8px;align-items:center;background:var(--s8);border:1px solid var(--s7);border-radius:9px;padding:8px 10px;font-size:13.5px}
.hg2-qty{background:var(--void);border:1px solid var(--s7);border-radius:7px;padding:6px;color:var(--silver);text-align:center;font-family:inherit;width:100%}
.hg2-quote-total{display:flex;justify-content:space-between;align-items:center;background:var(--s8);border:1px solid var(--s7);border-radius:11px;padding:13px 15px;margin-top:4px}
.hg2-quote-total b{font-family:'Rubik';font-weight:900;font-size:20px;color:var(--cyan)}
.hg2-mono{font-family:ui-monospace,monospace;font-variant-numeric:tabular-nums}
.hg2-commbtns{display:flex;gap:10px}
.hg2-commbtns .hg2-btn{flex:1}
.hg2-btn.disabled{opacity:.45;pointer-events:none}
.hg2-btn:disabled{opacity:.5;pointer-events:none}
.hg2-finrow{background:var(--s9);border:1px solid var(--s7);border-radius:12px;padding:12px 13px}
.hg2-finrow-top{display:flex;justify-content:space-between;align-items:baseline;margin-bottom:8px}
.hg2-finrow-top b{font-size:14.5px;font-weight:700}
.hg2-finrow-top span{font-family:ui-monospace,monospace;font-weight:700;font-size:13px}
.hg2-finrow-top .pos{color:var(--ok)}
.hg2-finrow-top .neg{color:var(--red)}
.hg2-finbar{height:6px;background:var(--s8);border-radius:4px;overflow:hidden;margin-bottom:4px}
.hg2-finbar span{display:block;height:100%;border-radius:4px}
.hg2-finbar span.inc{background:var(--cyan)}
.hg2-finbar span.exp{background:var(--amber)}
.hg2-finrow-meta{display:flex;gap:14px;font-size:11.5px;margin-top:5px}
.hg2-finrow-meta .cy{color:var(--cyan)}
.hg2-finrow-meta .am{color:var(--amber)}

/* interactive dashboard */
.hg2-kpis{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px}
.hg2-kpi{background:var(--s9);border:1px solid var(--s7);border-radius:13px;padding:13px 15px;animation:kpiIn .5s ease both}
.hg2-kpi.big{grid-column:1 / -1;background:linear-gradient(135deg,rgba(228,188,99,.14),var(--s9) 62%);border-color:rgba(228,188,99,.35)}
.hg2-kpi span{font-size:12px;color:var(--s4)}
.hg2-kpi b{display:block;font-family:'Rubik';font-weight:900;font-size:21px;margin-top:3px;font-variant-numeric:tabular-nums}
.hg2-kpi.big b{font-size:30px}
.hg2-kpi b.cy{color:var(--cyan)}
@keyframes kpiIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:none}}
.hg2-metrictog{margin-right:auto;display:flex;background:var(--s8);border:1px solid var(--s7);border-radius:9px;overflow:hidden}
.hg2-metrictog button{background:none;border:none;color:var(--s4);font-family:inherit;font-size:12px;font-weight:700;padding:6px 12px;cursor:pointer}
.hg2-metrictog button.on{background:var(--amber);color:#1A1206}
.hg2-trend{position:relative;margin-top:4px}
.hg2-trend-svg{width:100%;height:auto;display:block;touch-action:none}
.hg2-trend-line{stroke-dasharray:1;stroke-dashoffset:1;animation:draw 1.1s ease forwards}
@keyframes draw{to{stroke-dashoffset:0}}
.hg2-trend-x{fill:var(--s4);font-size:8px;font-family:'Heebo'}
.hg2-trend-tip{position:absolute;top:-2px;transform:translateX(50%);background:var(--void);border:1px solid var(--s7);border-radius:9px;padding:6px 10px;pointer-events:none;white-space:nowrap;box-shadow:0 4px 14px rgba(0,0,0,.4)}
.hg2-trend-tip b{display:block;font-size:11px;color:var(--s4);font-weight:600}
.hg2-trend-tip span{font-family:ui-monospace,monospace;font-weight:700;color:var(--cyan);font-size:14px}
.hg2-donutwrap{display:flex;align-items:center;gap:16px;flex-wrap:wrap}
.hg2-donut{width:150px;flex-shrink:0;margin:0 auto}
.hg2-donut svg{width:100%;height:auto;animation:donutIn .6s ease both}
@keyframes donutIn{from{opacity:0;transform:rotate(-12deg) scale(.9)}to{opacity:1;transform:none}}
.hg2-donut-seg{transition:stroke-width .2s}
.hg2-donut-c1{fill:var(--s4);font-size:11px;font-family:'Heebo';font-weight:700}
.hg2-donut-c2{fill:var(--silver);font-size:16px;font-family:'Rubik';font-weight:900}
.hg2-donut-legend{flex:1;min-width:130px;display:flex;flex-direction:column;gap:5px}
.hg2-leg{display:flex;align-items:center;gap:8px;background:none;border:1px solid transparent;border-radius:8px;padding:5px 7px;cursor:pointer;font-family:inherit;color:var(--silver);font-size:12.5px;text-align:right}
.hg2-leg.on{border-color:var(--s7);background:var(--s8)}
.hg2-leg i{width:10px;height:10px;border-radius:3px;flex-shrink:0}
.hg2-leg span{flex:1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.hg2-leg b{font-family:ui-monospace,monospace;color:var(--s4)}
.hg2-rank .hg2-bar.sm span{transition:width .9s cubic-bezier(.2,.7,.2,1)}

/* quote builder lines */
.hg2-qline{display:grid;grid-template-columns:1fr auto;grid-template-areas:"name x" "qty price" "sum sum";gap:8px 10px;background:var(--s8);border:1px solid var(--s7);border-radius:11px;padding:11px 12px}
.hg2-qline-name{grid-area:name;font-size:14px;font-weight:700;align-self:center}
.hg2-qline>.hg2-icbtn2{grid-area:x}
.hg2-qline label{display:flex;flex-direction:column;gap:3px;font-size:11px;color:var(--s4)}
.hg2-qline label:nth-of-type(1){grid-area:qty}
.hg2-qline label:nth-of-type(2){grid-area:price}
.hg2-qline label input{background:var(--void);border:1px solid var(--s7);border-radius:8px;padding:8px;color:var(--silver);font-family:inherit;font-size:14px;width:100%;outline:none}
.hg2-qline-sum{grid-area:sum;text-align:left;font-family:ui-monospace,monospace;font-weight:700;color:var(--cyan);border-top:1px dashed var(--s7);padding-top:7px}
.hg2-vatrow{display:flex;align-items:center;justify-content:space-between;background:var(--s8);border:1px solid var(--s7);border-radius:11px;padding:10px 14px;margin-top:6px}
.hg2-vatrow input{width:70px;background:var(--void);border:1px solid var(--s7);border-radius:8px;padding:7px;color:var(--silver);font-family:inherit;text-align:center;font-size:15px;outline:none}
.hg2-totals{background:var(--s9);border:1px solid var(--s7);border-radius:12px;padding:13px 15px;margin-top:8px}
.hg2-totals>div{display:flex;justify-content:space-between;align-items:center;padding:5px 0;font-size:14px;color:var(--s4)}
.hg2-totals>div b{color:var(--silver);font-family:ui-monospace,monospace}
.hg2-totals .tot{border-top:1px solid var(--s7);margin-top:5px;padding-top:11px;font-size:16px;color:var(--silver);font-weight:700}
.hg2-totals .tot b{font-family:'Rubik';font-weight:900;font-size:21px;color:var(--cyan)}

/* designed quote document — Heavy Guard brand */
.hg2-quotedoc{background:#fff;color:#1b2733;border-radius:14px;overflow:hidden;box-shadow:0 8px 30px rgba(0,0,0,.4)}
.hg2-qd-band{display:flex;gap:14px;background:linear-gradient(135deg,#bfe3e6,#d6eef0);padding:20px 18px}
.hg2-qd-brand{text-align:center;flex-shrink:0;width:118px}
.hg2-qd-logo{width:84px;height:84px;object-fit:contain;margin:0 auto}
.hg2-qd-name{font-family:'Rubik',sans-serif;font-weight:900;font-size:18px;color:#16313a;margin-top:4px;letter-spacing:.5px}
.hg2-qd-co{font-size:10.5px;line-height:1.7;color:#2c4a52;margin-top:5px}
.hg2-qd-titlebox{flex:1;text-align:right;padding-top:4px}
.hg2-qd-title{font-family:'Rubik';font-weight:900;font-size:30px;color:#16313a;line-height:1}
.hg2-qd-num{font-size:13px;color:#2c4a52;margin:4px 0 12px}
.hg2-qd-meta{font-size:13px;color:#1b2733;line-height:1.7}
.hg2-qd-meta b{font-size:15px}
.hg2-qd-table{width:100%;border-collapse:collapse;font-size:12.5px;margin-top:4px}
.hg2-qd-table th{color:#5a6b78;font-weight:700;padding:11px 10px;text-align:right;border-bottom:1.5px solid #cfd8e0}
.hg2-qd-table th:nth-child(n+2),.hg2-qd-table td:nth-child(n+2){text-align:center}
.hg2-qd-table td{padding:13px 10px;border-bottom:1px solid #eef1f5;font-family:ui-monospace,monospace;vertical-align:top}
.hg2-qd-table td:first-child{font-family:'Heebo',sans-serif;font-weight:600;text-align:right;line-height:1.5}
.hg2-qd-sums{padding:4px 10px}
.hg2-qd-sums>div{display:flex;justify-content:space-between;align-items:center;padding:7px 0;font-size:13.5px;font-weight:700;color:#1b2733}
.hg2-qd-sums>div b{font-family:ui-monospace,monospace}
.hg2-qd-sums .tot{border-top:1px solid #e3e8ee;font-size:15px}
.hg2-qd-sums .tot b{color:#0e7d8c;font-size:17px}
.hg2-qd-sec{padding:14px 10px 4px;font-size:13px;font-weight:700;text-decoration:underline;color:#1b2733}
.hg2-qd-list{margin:0;padding:0 28px 0 10px;font-size:12.5px;color:#2c4a52;line-height:1.9}
.hg2-qd-pay{padding:2px 10px;font-size:12.5px;color:#2c4a52;line-height:1.6}
.hg2-qd-foot{text-align:center;font-size:12.5px;color:#5a6b78;padding:16px 10px}
.hg2-qd-bottomband{height:18px;background:linear-gradient(135deg,#bfe3e6,#d6eef0)}
@media print{
  body *{visibility:hidden!important}
  #quotedoc,#quotedoc *{visibility:visible!important}
  #quotedoc{position:absolute;inset:0;margin:0;box-shadow:none;border-radius:0}
}

/* confirm dialog */
.hg2-confirm{background:var(--s9);border:1px solid var(--s7);border-radius:16px;padding:20px;max-width:340px;width:100%}
.hg2-confirm-msg{font-size:15px;line-height:1.55;margin-bottom:17px;white-space:pre-line}
.hg2-confirm-btns{display:flex;gap:10px}
.hg2-confirm-btns .hg2-btn{flex:1}

/* date field + calendar */
.hg2-datebtn{display:flex;align-items:center;gap:8px;width:100%;background:var(--s9);border:1.5px solid var(--s7);border-radius:11px;padding:12px 13px;color:var(--silver);font-family:inherit;font-size:15px;cursor:pointer;text-align:right}
.hg2-datebtn svg{color:var(--cyan)}
.hg2-calmodal{background:var(--s9);border:1px solid var(--s7);border-radius:16px;padding:14px;max-width:330px;width:100%}
.hg2-cal-head{display:flex;align-items:center;justify-content:space-between;margin-bottom:10px}
.hg2-cal-head b{font-family:'Rubik';font-weight:700;font-size:16px}
.hg2-cal-head button{width:34px;height:34px;border-radius:9px;background:var(--s8);border:1px solid var(--s7);color:var(--silver);display:flex;align-items:center;justify-content:center;cursor:pointer}
.hg2-cal-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:4px}
.hg2-cal-wd{text-align:center;font-size:11px;color:var(--s4);font-weight:700;padding-bottom:4px}
.hg2-cal-day{aspect-ratio:1;border:none;background:var(--s8);color:var(--silver);border-radius:9px;font-family:inherit;font-size:14px;cursor:pointer;position:relative;display:flex;align-items:center;justify-content:center}
.hg2-cal-day.today{border:1.5px solid var(--cyan)}
.hg2-cal-day.sel{background:var(--amber);color:#1A1206;font-weight:900}
.hg2-cal-day.mark::after{content:"";position:absolute;bottom:4px;left:50%;transform:translateX(-50%);width:5px;height:5px;border-radius:50%;background:var(--amber)}
.hg2-cal-day.sel.mark::after{background:#1A1206}
.hg2-cal-clear{width:100%;margin-top:10px;background:var(--s8);border:1px solid var(--s7);color:var(--s4);border-radius:9px;padding:9px;font-family:inherit;cursor:pointer}
.hg2-calwrap{background:var(--s9);border:1px solid var(--s7);border-radius:14px;padding:14px;margin-bottom:14px}
.hg2-callegend{display:flex;gap:16px;justify-content:center;margin-top:11px;font-size:11px;color:var(--s4)}
.hg2-callegend span{display:flex;align-items:center;gap:5px}
.hg2-callegend i{width:9px;height:9px;border-radius:50%;display:inline-block}
.hg2-callegend i.d-mark{background:var(--amber)}
.hg2-callegend i.d-today{background:none;border:1.5px solid var(--cyan)}

/* installs in agenda */
.hg2-instrow{display:flex;align-items:center;gap:11px;background:var(--s9);border:1px solid var(--s7);border-radius:11px;padding:11px 13px}
.hg2-cdot{width:11px;height:11px;border-radius:50%;flex-shrink:0}
.hg2-instrow-mid{flex:1;min-width:0;display:flex;flex-direction:column;gap:2px}
.hg2-instrow-mid b{font-size:14px;font-weight:700;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.hg2-instrow-mid span{font-size:12px;color:var(--s4)}
.hg2-instrow-p{font-family:ui-monospace,monospace;font-weight:700;color:var(--cyan);font-size:13px;flex-shrink:0}
.hg2-ta{width:100%;background:var(--s9);border:1.5px solid var(--s7);border-radius:11px;padding:11px 13px;color:var(--silver);font-family:inherit;font-size:14px;outline:none;resize:vertical;line-height:1.5}
.hg2-ta:focus{border-color:var(--cyan)}

/* reminders */
.hg2-remind{display:flex;align-items:flex-start;gap:10px;background:rgba(228,188,99,.08);border:1px solid rgba(228,188,99,.3);color:#F3B85A;border-radius:12px;padding:13px 15px;margin-bottom:16px;font-size:13px;line-height:1.6}
.hg2-remind svg{flex-shrink:0;color:var(--amber);margin-top:1px}

/* agenda */
.hg2-daystrip{display:flex;gap:8px;overflow-x:auto;padding:4px 0 8px;scrollbar-width:none}
.hg2-daystrip::-webkit-scrollbar{display:none}
.hg2-day{flex-shrink:0;min-width:60px;background:var(--s9);border:1px solid var(--s7);border-radius:12px;padding:9px 6px;text-align:center;cursor:pointer;position:relative;font-family:inherit;color:var(--silver)}
.hg2-day.on{border-color:var(--amber);background:rgba(228,188,99,.08)}
.hg2-day b{display:block;font-family:'Rubik';font-weight:700;font-size:13px}
.hg2-day span{font-size:10.5px;color:var(--s4)}
.hg2-day .cnt{position:absolute;top:-6px;left:-6px;background:var(--amber);color:#1A1206;font-size:10px;font-weight:700;min-width:18px;height:18px;border-radius:9px;display:flex;align-items:center;justify-content:center;padding:0 4px}
.hg2-jump{display:flex;align-items:center;gap:8px;font-size:12.5px;color:var(--s4);margin-bottom:13px}
.hg2-jump svg{color:var(--cyan)}
.hg2-jump input{background:var(--s9);border:1px solid var(--s7);border-radius:9px;padding:7px 10px;color:var(--silver);font-family:inherit;font-size:13px}
.hg2-addbar{display:flex;gap:8px;margin-bottom:16px}
.hg2-addbar input{flex:1;background:var(--s9);border:1.5px solid var(--s7);border-radius:11px;padding:13px;color:var(--silver);font-size:15px;font-family:inherit;outline:none}
.hg2-addbar input:focus{border-color:var(--cyan)}
.hg2-addbar button{background:var(--amber);color:#1A1206;border:none;border-radius:11px;width:50px;display:flex;align-items:center;justify-content:center;cursor:pointer;flex-shrink:0}
.hg2-task{display:flex;align-items:center;gap:11px;background:var(--s9);border:1px solid var(--s7);border-radius:11px;padding:12px 13px}
.hg2-task.done{opacity:.55}
.hg2-check{width:25px;height:25px;border-radius:50%;border:2px solid var(--s7);background:none;display:flex;align-items:center;justify-content:center;cursor:pointer;flex-shrink:0;color:transparent;padding:0}
.hg2-task.done .hg2-check{background:var(--ok);border-color:var(--ok);color:#fff}
.hg2-task-title{flex:1;font-size:14.5px;line-height:1.4}
.hg2-task.done .hg2-task-title{text-decoration:line-through}
.hg2-cntbadge{margin-right:6px;background:var(--amber);color:#1A1206;font-size:11px;font-weight:700;min-width:18px;height:18px;border-radius:9px;display:inline-flex;align-items:center;justify-content:center;padding:0 5px}

/* stock / suppliers / invoices */
.hg2-row2{display:grid;grid-template-columns:1fr 1fr;gap:12px}
.hg2-crow.low{border-color:rgba(228,188,99,.5)}
.hg2-crow-ic.warn{color:var(--amber)}
.hg2-ownerbadge{display:inline-block;border:1px solid;border-radius:6px;padding:0 6px;font-size:10.5px;font-weight:700}
.hg2-fdot{width:8px;height:8px;border-radius:50%;display:inline-block;margin-left:5px}
.hg2-sumrow{display:flex;align-items:center;gap:9px;padding:8px 0;border-bottom:1px solid var(--s7)}
.hg2-sumrow:last-child{border:none;padding-bottom:0}
.hg2-sumrow-l{flex:1;font-size:13.5px;font-weight:700}
.hg2-sumrow-u{font-size:11.5px;color:var(--s4)}
.hg2-sumrow-v{font-family:ui-monospace,monospace;font-weight:700;color:var(--cyan);font-size:13px;min-width:64px;text-align:left}
.hg2-sumrow.tot{border-top:1px solid var(--s7);margin-top:3px;padding-top:10px}
.hg2-sumrow.tot .hg2-sumrow-l{font-weight:900}
.hg2-sumrow.tot .hg2-sumrow-v{font-size:15px}
.hg2-stepper{display:flex;align-items:center;gap:4px;flex-shrink:0}
.hg2-stepper button{width:30px;height:30px;border-radius:8px;background:var(--s8);border:1px solid var(--s7);color:var(--silver);display:flex;align-items:center;justify-content:center;cursor:pointer}
.hg2-stepper b{min-width:30px;text-align:center;font-family:'Rubik';font-weight:900;font-size:17px}
.hg2-stepper b.lo{color:var(--amber)}
.hg2-sup{display:flex;align-items:center;gap:10px;padding:10px 0;border-bottom:1px solid var(--s7)}
.hg2-sup:last-child{border:none;padding-bottom:0}
.hg2-sup.best .hg2-sup-mid b{color:var(--ok)}
.hg2-sup-tr{color:var(--amber);flex-shrink:0}
.hg2-sup-mid{flex:1;min-width:0;display:flex;flex-direction:column;gap:2px}
.hg2-sup-mid b{font-size:14px;font-weight:700}
.hg2-sup-mid span{font-size:11.5px;color:var(--s4)}
.hg2-sup-save{color:var(--ok)!important;font-weight:700}
.hg2-sup-price{font-family:ui-monospace,monospace;font-weight:700;font-size:14.5px;flex-shrink:0}
.hg2-crow-thumb{width:42px;height:42px;border-radius:9px;overflow:hidden;flex-shrink:0;background:var(--s8);display:flex;align-items:center;justify-content:center;color:var(--s4)}
.hg2-crow-thumb img{width:100%;height:100%;object-fit:cover}
.hg2-inv-right{display:flex;flex-direction:column;align-items:flex-end;gap:4px;flex-shrink:0}
.hg2-statuspill{border:none;cursor:pointer;font-family:inherit;font-size:10.5px;font-weight:700;padding:3px 9px;border-radius:20px}
.hg2-statuspill.paid{background:rgba(53,208,138,.15);color:var(--ok)}
.hg2-statuspill.pend{background:rgba(228,188,99,.15);color:var(--amber)}
.hg2-wa{width:32px;height:32px;border-radius:8px;background:rgba(53,208,138,.14);color:var(--ok);display:flex;align-items:center;justify-content:center;text-decoration:none;border:none;cursor:pointer}

/* trips map */
.hg2-tripsec{display:flex;flex-direction:column}
.hg2-daterow{display:flex;gap:10px;margin:4px 0 10px}
.hg2-daterow label{flex:1;display:flex;align-items:center;gap:7px;font-size:12.5px;color:var(--s4);background:var(--s9);border:1px solid var(--s7);border-radius:10px;padding:8px 11px}
.hg2-daterow input{flex:1;background:none;border:none;color:var(--silver);font-family:inherit;font-size:13px;outline:none}
.hg2-mapstat{display:flex;gap:16px;font-size:12.5px;color:var(--s4);margin-bottom:10px}
.hg2-mapstat span{display:flex;align-items:center;gap:4px}
.hg2-tripsum{display:grid;grid-template-columns:repeat(2,1fr);gap:8px;margin-bottom:10px}
.hg2-sumcard{display:flex;flex-direction:column;align-items:center;gap:2px;background:var(--s9);border:1px solid var(--s7);border-radius:12px;padding:11px 8px}
.hg2-sumcard svg{color:var(--amber)}
.hg2-sumcard b{font-size:18px;color:var(--silver);font-family:'Rubik',sans-serif}
.hg2-sumcard span{font-size:11px;color:var(--s4)}
.hg2-fuelrow{display:flex;gap:10px;margin-bottom:12px}
.hg2-fuelrow label{flex:1;display:flex;align-items:center;gap:6px;font-size:12px;color:var(--s4);background:var(--s9);border:1px solid var(--s7);border-radius:10px;padding:6px 10px}
.hg2-fuelrow input{width:54px;background:var(--s8);border:1px solid var(--s7);border-radius:7px;color:var(--silver);font-family:inherit;font-size:13px;padding:4px 6px;text-align:center}
.hg2-tripday-km{display:flex;align-items:center;gap:5px;font-size:11.5px;color:var(--amber);margin-top:5px}
.hg2-grp{border:1px solid var(--s7);border-radius:12px;margin-bottom:8px;overflow:hidden;background:var(--s9)}
.hg2-grphead{width:100%;display:flex;align-items:center;justify-content:space-between;gap:8px;background:none;border:none;color:var(--silver);font-family:inherit;padding:11px 13px;cursor:pointer;text-align:right}
.hg2-grplbl{display:flex;align-items:center;gap:6px;font-weight:700;font-size:14px}
.hg2-grpstat{font-size:11px;color:var(--amber);white-space:nowrap}
.hg2-grpdays{padding:0 8px 8px;display:flex;flex-direction:column;gap:8px}
.hg2-grpdays .hg2-tripday{background:var(--s8)}
.hg2-mapbox{position:relative;height:340px;border-radius:14px;overflow:hidden;border:1px solid var(--s7);background:#0E141C;z-index:0;isolation:isolate}
.hg2-mapbox .leaflet-pane,.hg2-mapbox .leaflet-top,.hg2-mapbox .leaflet-bottom,.hg2-mapbox .leaflet-control{z-index:1!important}
.hg2-svgmap{position:relative;background:radial-gradient(120% 90% at 50% 0%,#141C28,#0C1118 80%);border:1px solid var(--s7);border-radius:14px;padding:12px;display:flex;justify-content:center;min-height:300px}
.hg2-svgmap-svg{height:330px;width:auto;max-width:100%;display:block}
.hg2-mappin-lbl{fill:var(--champ);font-size:9px;font-weight:700;font-family:'Heebo';paint-order:stroke;stroke:#0B0F14;stroke-width:2.5px}
.hg2-mapbase-lbl{fill:var(--cyan);font-size:8px;font-weight:700;font-family:'Heebo';paint-order:stroke;stroke:#0B0F14;stroke-width:2.5px}
.hg2-mapsel{position:absolute;top:14px;right:14px;z-index:2;background:rgba(8,11,16,.85);border:1px solid rgba(228,188,99,.4);border-radius:10px;padding:7px 12px;text-align:right}
.hg2-mapsel b{display:block;font-size:13px;color:var(--champ)}
.hg2-mapsel span{font-size:11px;color:var(--s4)}
.hg2-mapel{position:absolute;inset:0;background:#0E141C}
.hg2-maploading{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;color:var(--s4);font-size:13px}
.hg2-mapfail{text-align:center;color:var(--s4);padding:34px 18px;background:var(--s9);border:1px solid var(--s7);border-radius:14px}
.hg2-mapfail svg{opacity:.5;margin-bottom:8px}
.hg2-mapfail div{font-weight:700;color:var(--silver)}
.hg2-mapfail p{font-size:13px;margin-top:4px}
.leaflet-popup-content-wrapper,.leaflet-popup-tip{background:var(--s8);color:var(--silver)}

/* CRM Leads */
.crm-head-logo{width:34px;height:34px;object-fit:contain;border-radius:8px;margin-left:4px;margin-right:-4px}
.crm-stats{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin:14px 0 10px}
.crm-stat{background:var(--s9);border:1px solid var(--s7);border-radius:11px;padding:10px 8px;text-align:center}
.crm-stat b{display:block;font-family:'Rubik';font-weight:900;font-size:18px;color:var(--silver)}
.crm-stat span{font-size:10px;color:var(--s4);margin-top:2px;display:block}
.crm-stat.won b{color:var(--ok)}
.crm-search-row{margin:10px 0 6px}
.crm-searchbox{display:flex;align-items:center;gap:8px;background:var(--s9);border:1px solid var(--s7);border-radius:11px;padding:9px 12px}
.crm-searchbox svg{color:var(--s4);flex-shrink:0}
.crm-searchbox input{flex:1;background:none;border:none;outline:none;color:var(--silver);font-family:inherit;font-size:14px;text-align:right}
.crm-searchbox input::placeholder{color:var(--s5)}
.crm-searchbox button{background:none;border:none;color:var(--s4);padding:0;cursor:pointer}
.crm-chips-row{display:flex;flex-wrap:nowrap;gap:6px;overflow-x:auto;margin-bottom:7px;padding-bottom:2px;scrollbar-width:none}
.crm-chips-row::-webkit-scrollbar{display:none}
.crm-chips-row button{flex-shrink:0;background:var(--s9);border:1px solid var(--s7);border-radius:20px;color:var(--s4);padding:5px 12px;font-family:inherit;font-size:12.5px;font-weight:700;cursor:pointer;white-space:nowrap}
.crm-chips-row button.on{background:rgba(228,188,99,.15);border-color:var(--amber);color:var(--amber)}
.crm-chips-row.small button{font-size:11.5px;padding:4px 10px}
.crm-chips-row.small button.on{background:color-mix(in srgb,var(--sc) 18%,transparent);border-color:var(--sc);color:var(--sc)}
.crm-count{font-size:12px;color:var(--s4);margin-bottom:8px;text-align:right}
.crm-card{width:100%;background:var(--s9);border:1px solid var(--s7);border-radius:13px;padding:12px 13px;margin-bottom:8px;text-align:right;font-family:inherit;color:var(--silver);cursor:pointer;display:block}
.crm-card:active{border-color:var(--amber)}
.crm-card-top{display:flex;align-items:flex-start;justify-content:space-between;gap:8px;margin-bottom:6px}
.crm-card-name{font-size:14px;font-weight:700;flex:1;min-width:0;line-height:1.35}
.crm-badge{font-size:10.5px;font-weight:700;border-radius:20px;padding:2px 8px;white-space:nowrap;flex-shrink:0}
.crm-card-meta{display:flex;flex-wrap:wrap;gap:6px;font-size:11.5px;color:var(--s4);margin-bottom:5px;align-items:center}
.crm-card-meta svg{display:inline;vertical-align:middle;margin-left:2px}
.crm-geo-tag{background:var(--s8);border:1px solid var(--s7);border-radius:8px;padding:1px 6px;font-size:10.5px}
.crm-card-sector{font-size:11.5px;color:var(--s5);margin-bottom:6px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.crm-card-bottom{display:flex;align-items:center;gap:8px}
.crm-score-wrap{display:flex;align-items:center;gap:5px;flex:1}
.crm-score-wrap span{font-size:11px;color:var(--s4);flex-shrink:0}
.crm-score-bar{flex:1;height:4px;background:var(--s7);border-radius:2px;overflow:hidden}
.crm-score-bar div{height:100%;border-radius:2px;transition:width .3s}
.crm-score-bar.big{height:6px;flex:1}
.crm-log-badge{background:rgba(228,188,99,.15);border:1px solid rgba(228,188,99,.3);color:var(--amber);font-size:10px;font-weight:700;border-radius:20px;padding:2px 6px;display:flex;align-items:center;gap:3px}
.crm-mine-badge{background:rgba(34,197,94,.12);border:1px solid rgba(34,197,94,.3);color:#22c55e;font-size:10px;font-weight:700;border-radius:20px;padding:2px 6px}
.crm-more-btn{width:100%;padding:12px;background:var(--s9);border:1px solid var(--s7);border-radius:11px;color:var(--cyan);font-family:inherit;font-size:13px;font-weight:700;cursor:pointer;margin-top:4px}
.crm-empty-state{text-align:center;padding:40px 20px;color:var(--s4)}
.crm-empty-state svg{margin-bottom:10px;opacity:.4}
.crm-score-detail{display:flex;align-items:center;gap:10px;background:var(--s9);border:1px solid var(--s7);border-radius:11px;padding:10px 14px;margin-bottom:12px}
.crm-score-detail span{font-size:12px;color:var(--s4);flex-shrink:0}
.crm-score-detail b{font-size:20px;font-weight:900;font-family:'Rubik';flex-shrink:0}
.crm-pipeline{display:flex;flex-wrap:wrap;gap:6px;margin-bottom:14px}
.crm-pipe-step{flex:1;min-width:calc(33.33% - 4px);background:var(--s9);border:1px solid var(--s7);border-radius:20px;color:var(--s4);padding:6px 8px;font-family:inherit;font-size:11px;font-weight:700;cursor:pointer;text-align:center}
.crm-pipe-step.on{background:color-mix(in srgb,var(--sc) 20%,transparent);border-color:var(--sc);color:var(--sc)}
.crm-section{background:var(--s9);border:1px solid var(--s7);border-radius:13px;padding:12px 14px;margin-bottom:10px}
.crm-section-ttl{font-size:11.5px;font-weight:700;color:var(--s4);margin-bottom:8px;text-transform:uppercase;letter-spacing:.5px}
.crm-section-ttl-row{display:flex;align-items:center;justify-content:space-between;margin-bottom:8px}
.crm-contact-row{display:flex;align-items:center;gap:8px;width:100%;padding:7px 0;border-bottom:1px solid rgba(43,53,67,.5);text-decoration:none;color:var(--silver);background:none;border-left:none;border-right:none;border-top:none;font-family:inherit;font-size:13px;cursor:pointer;text-align:right}
.crm-contact-row:last-child{border-bottom:none}
.crm-contact-row svg{color:var(--s4);flex-shrink:0}
.crm-contact-row span{flex:1;min-width:0}
.crm-contact-action{color:var(--cyan);font-size:11.5px;font-weight:700;flex-shrink:0}
.crm-info-row{display:flex;align-items:flex-start;gap:7px;font-size:12.5px;color:var(--s4);padding:4px 0;line-height:1.4}
.crm-info-row svg{flex-shrink:0;margin-top:1px}
.crm-truncate{overflow:hidden;text-overflow:ellipsis;white-space:nowrap;flex:1;min-width:0}
.crm-mgr{padding:7px 0;border-bottom:1px solid rgba(43,53,67,.5)}
.crm-mgr:last-child{border-bottom:none}
.crm-mgr-top{display:flex;align-items:center;gap:8px;margin-bottom:3px}
.crm-mgr-name{font-size:13px;font-weight:700}
.crm-mgr-role{font-size:11px;color:var(--s4);background:var(--s8);border:1px solid var(--s7);border-radius:8px;padding:2px 6px}
.crm-mgr-email{display:flex;align-items:center;gap:5px;color:var(--cyan);font-size:11.5px;text-decoration:none}
.crm-notes-area{width:100%;background:var(--s8);border:1px solid var(--s7);border-radius:9px;padding:9px 11px;color:var(--silver);font-family:inherit;font-size:13px;resize:none;outline:none;box-sizing:border-box;margin-bottom:8px}
.crm-notes-area:focus{border-color:var(--cyan)}
.crm-save-btn{background:var(--cyan);color:#0B0F14;border:none;border-radius:9px;padding:8px 18px;font-family:inherit;font-size:13px;font-weight:700;cursor:pointer}
.crm-cancel-btn{background:var(--s8);color:var(--s4);border:1px solid var(--s7);border-radius:9px;padding:8px 14px;font-family:inherit;font-size:13px;cursor:pointer}
.crm-add-btn{background:rgba(228,188,99,.15);border:1px solid rgba(228,188,99,.3);color:var(--amber);border-radius:20px;padding:4px 12px;font-family:inherit;font-size:12px;font-weight:700;cursor:pointer}
.crm-add-form{background:var(--s8);border:1px solid var(--s7);border-radius:11px;padding:11px;margin-bottom:10px}
.crm-form-row{display:flex;gap:8px;margin-bottom:8px}
.crm-select{flex:1;background:var(--s9);border:1px solid var(--s7);border-radius:8px;padding:7px 9px;color:var(--silver);font-family:inherit;font-size:12.5px;outline:none}
.crm-empty{font-size:12.5px;color:var(--s5);padding:8px 0}
.crm-orig-notes{font-size:12px;color:var(--s4);line-height:1.6;white-space:pre-wrap}
.crm-out-entry{padding:9px 0;border-bottom:1px solid rgba(43,53,67,.5)}
.crm-out-entry:last-child{border-bottom:none}
.crm-out-header{display:flex;align-items:center;gap:7px;margin-bottom:4px}
.crm-out-type{background:rgba(111,211,240,.12);color:var(--cyan);border-radius:8px;padding:2px 7px;font-size:11px;font-weight:700}
.crm-out-result{border-radius:8px;padding:2px 7px;font-size:11px;font-weight:700}
.crm-out-result.r-חיובי{background:rgba(34,197,94,.12);color:#22c55e}
.crm-out-result.r-שלילי{background:rgba(239,68,68,.12);color:#ef4444}
.crm-out-result.r-מעניין{background:rgba(139,92,246,.12);color:#8b5cf6}
.crm-out-result.r-אין-מענה,.crm-out-result.r-לחזור{background:rgba(107,114,128,.12);color:#9ca3af}
.crm-out-date{font-size:11px;color:var(--s4);margin-right:auto}
.crm-out-notes{font-size:12.5px;color:var(--silver);line-height:1.5}
.leaflet-popup-content{font-family:'Heebo',sans-serif;direction:rtl}
.hg2-tripday{display:flex;gap:11px;background:var(--s9);border:1px solid var(--s7);border-radius:11px;padding:11px 13px;width:100%;text-align:right;font-family:inherit;color:var(--silver);cursor:pointer;align-items:flex-start}
.hg2-tripday:active{border-color:var(--cyan)}
.hg2-tripday-date{font-family:ui-monospace,monospace;font-weight:700;color:var(--cyan);font-size:13px;flex-shrink:0;min-width:58px;display:flex;flex-direction:column;align-items:flex-start;gap:3px}
.hg2-tripday-date svg{color:var(--s4)}
.hg2-tripday-locs{display:flex;flex-wrap:wrap;gap:6px}
.hg2-triploc{display:inline-flex;align-items:center;gap:3px;background:var(--s8);border:1px solid var(--s7);border-radius:8px;padding:3px 8px;font-size:12px}
.hg2-triploc svg{color:var(--amber)}

/* day route */
.hg2-routesum{display:grid;grid-template-columns:1fr 1fr 1fr;gap:9px;margin:16px 0}
.hg2-routesum>div{background:var(--s8);border:1px solid var(--s7);border-radius:11px;padding:11px 8px;text-align:center}
.hg2-routesum span{font-size:11px;color:var(--s4);display:block}
.hg2-routesum b{font-family:'Rubik';font-weight:900;font-size:18px;margin-top:3px;display:block}
.hg2-route{display:flex;flex-direction:column;position:relative}
.hg2-rstop{display:flex;align-items:center;gap:11px;padding:7px 0;position:relative}
.hg2-rstop>div{flex:1;display:flex;flex-direction:column;gap:1px}
.hg2-rstop b{font-size:14px;font-weight:700}
.hg2-rstop em{font-style:normal;font-size:11.5px;color:var(--s4)}
.hg2-rdot{width:26px;height:26px;border-radius:50%;background:var(--amber);color:#1A1206;display:flex;align-items:center;justify-content:center;font-weight:900;font-size:12px;flex-shrink:0;order:2}
.hg2-rstop.base .hg2-rdot{background:var(--cyan)}
.hg2-rstop>div{order:3}
.hg2-rleg{order:1;font-size:11px;color:var(--s4);background:var(--s8);border:1px solid var(--s7);border-radius:20px;padding:3px 9px;white-space:nowrap;flex-shrink:0}

/* week comparison */
.hg2-weekcmp{background:var(--s9);border:1px solid var(--s7);border-radius:14px;padding:14px 15px;margin-bottom:14px}
.hg2-weekcmp-ttl{display:flex;align-items:center;gap:7px;font-size:12.5px;color:var(--s4);font-weight:700;margin-bottom:12px}
.hg2-weekcmp-ttl svg{color:var(--amber)}
.hg2-weekcmp-cols{display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px}
.hg2-weekcmp-col{display:flex;flex-direction:column;gap:3px}
.hg2-weekcmp-col span{font-size:11px;color:var(--s4)}
.hg2-weekcmp-col b{font-family:'Rubik';font-weight:900;font-size:16px;color:var(--silver)}
.hg2-weekcmp-col.dim b{color:var(--s4)}
.hg2-weekcmp-col em{font-style:normal;font-size:10.5px;display:flex;align-items:center;gap:3px;font-weight:700}
.hg2-weekcmp-col em.pos{color:var(--ok)}
.hg2-weekcmp-col em.neg{color:var(--red)}
.hg2-weekcmp-col em.dim,.hg2-weekcmp-col.dim em{color:var(--s4);font-weight:400}

/* hub today tasks */
.hg2-today-tasks{background:linear-gradient(135deg,rgba(111,211,240,.06),var(--s9) 70%);border:1px solid rgba(111,211,240,.22);border-radius:14px;padding:14px 15px;margin-bottom:18px}
.hg2-hub-task{display:flex;align-items:center;gap:11px;padding:8px 0;border-bottom:1px solid rgba(43,53,67,.6);cursor:pointer;user-select:none}
.hg2-hub-task:last-of-type{border-bottom:none}
.hg2-hub-task.done span{text-decoration:line-through;opacity:.5}
.hg2-hub-task .open-ic{color:var(--s7)}
.hg2-hub-task.done .done-ic{color:var(--ok)}
.hg2-hub-task span{flex:1;font-size:14px;line-height:1.4}
.hg2-today-more{margin-right:auto;background:none;border:none;color:var(--cyan);font-size:12px;font-weight:700;cursor:pointer;display:flex;align-items:center;gap:2px;padding:0}
.hg2-today-more-btn{width:100%;background:none;border:none;color:var(--cyan);font-size:12.5px;font-weight:700;cursor:pointer;padding:8px 0 2px;text-align:center}
`}</style>;
}
